window.RSS_ARTICLES = [{"title":"From anxiety to advantage: A marketing organization that thrives with AI","title_pt":null,"url":"https://www.mckinsey.com/capabilities/growth-marketing-and-sales/our-insights/from-anxiety-to-advantage-a-marketing-organization-that-thrives-with-ai","summary":"Marketers are using AI, but surface-level enthusiasm is masking the anxiety, indecision, and operating-model gaps holding back meaningful change.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-22","pub_date":"2026-06-22"},{"title":"From campaigns to continuous growth: AI capabilities shaping marketing","title_pt":null,"url":"https://www.mckinsey.com/capabilities/growth-marketing-and-sales/our-insights/from-campaigns-to-continuous-growth-ai-capabilities-shaping-marketing","summary":"Capabilities built around insights, creativity, personalization, agentic commerce, and orchestration form the five core pillars of the future of marketing.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-22","pub_date":"2026-06-22"},{"title":"ISG nomeia a Oracle como líder do Guia para Compradores de Plataformas de IA e Dados","title_pt":"ISG nomeia a Oracle como líder do Guia para Compradores de Plataformas de IA e Dados","url":"https://tiinside.com.br/19/06/2026/isg-nomeia-a-oracle-como-lider-do-guia-para-compradores-de-plataformas-de-ia-e-dados/","summary":"O ISG reconheceu a Oracle como Exemplar em nove relatórios, incluindo IA e Plataformas de Dados, Agentes de IA, Governança e Operações de IA, IA Agential e Gerativa, e IA e Dados Soberanos. \"A rápida adoção da IA agente está mudando as expectativas empresariais tanto para IA quanto para plataformas de dados\", disse David Menninger, diretor executivo e analista distinto da ISG. \"O desempenho de ...","summary_pt":"O ISG reconheceu a Oracle como Exemplar em nove relatórios, incluindo IA e Plataformas de Dados, Agentes de IA, Governança e Operações de IA, IA Agential e Gerativa, e IA e Dados Soberanos. \"A rápida adoção da IA agente está mudando as expectativas empresariais tanto para IA quanto para plataformas de dados\", disse David Menninger, diretor executivo e analista distinto da ISG. \"O desempenho de alto nível da Oracle, combinado com o reconhecimento em nível Exemplar em múltiplos relatórios, reflete uma abordagem pronta para empresas ao ajudar organizações a construir sistemas coesos para resultados de IA, relevantes e personalizados em tempo real.\"\nT.K. Anand, vice-presidente executivo da Oracle, complementa: \"A Oracle AI Data Platform ajuda organizações a levar a IA para onde seus dados vivem, fundamentar a IA generativa e agente no contexto empresarial, e passar da experimentação para a produção com a segurança, confiabilidade e escala que as empresas exigem. Temos orgulho de sermos reconhecidos pela ISG como o Líder Geral e acreditamos que isso demonstra nosso compromisso em ajudar os clientes a escalar com sucesso a IA.\"","source_id":"tiinside","first_seen":"2026-06-19","pub_date":"2026-06-19"},{"title":"Putting AI to work: The operational excellence imperative","title_pt":null,"url":"https://www.mckinsey.com/capabilities/operations/our-insights/putting-ai-to-work-the-operational-excellence-imperative","summary":"Our survey uncovers how operational excellence becomes the hidden accelerator of AI at scale.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-19","pub_date":"2026-06-19"},{"title":"QuintoAndar inaugura novo escritório e anuncia investimento de R$ 2 bilhões em tecnologia","title_pt":"QuintoAndar inaugura novo escritório e anuncia investimento de R$ 2 bilhões em tecnologia","url":"https://tiinside.com.br/19/06/2026/quintoandar-inaugura-novo-escritorio-e-anuncia-investimento-de-r-2-bilhoes-em-tecnologia/","summary":"O QuintoAndar inaugurou, nesta quinta-feira (19), o seu novo escritório e anunciou um investimento de R$ 2 bilhões em tecnologia para os próximos 2 anos. O espaço, localizado na Vila Leopoldina, possui mais de 7.000m², 400 workstations e \" faz parte da estratégia de inovação e expansão do QuintoAndar\".","summary_pt":"O QuintoAndar inaugurou, nesta quinta-feira (19), o seu novo escritório e anunciou um investimento de R$ 2 bilhões em tecnologia para os próximos 2 anos. O espaço, localizado na Vila Leopoldina, possui mais de 7.000m², 400 workstations e \" faz parte da estratégia de inovação e expansão do QuintoAndar\".\nO CEO da companhia, Gabriel Braga, afirma que o investimento e a nova instalação integram a visão do QuintoAndar de que a tecnologia e a IA irão \"redefinir o mercado imobiliário\". \"Tecnologia e inteligência artificial vão redefinir a forma como as pessoas encontram, negociam e vivem em seus lares. Estamos investindo para resolver problemas reais de milhões de pessoas\", aponta.\nDeborah Abi-Saber, CHRO do QuintoAndar, ressalta que o processo de integração de IA foi cadenciado, com foco na imersão da liderança e na criação de grupos de trabalho para ajudar a disseminar o uso das ferramentas. Segundo a executiva, a empresa saiu da fase de adoção inicial e busca escalabilidade e ROI.\n\"Nós estamos super bem posicionados para colocar a IA para ganhar escalabilidade e ganhar mais velocidade na solução dos problemas para os clientes, mantendo a segurança. Ainda não temos números sobre ROI, mas estamos confiantes que é o momento de ganhar escalabilidade e de entender os impactos reais da IA\", explica.\nA CHRO enfatiza que o QuintoAndar já possui um agente de IA conversacional, porém o destaque é dedicado ao agente _Performa,_ criado para ajudar líderes a redigir avaliações de desempenho e responsável pela economia de 66 horas na operação. Contudo, a executiva ressalta que a IA possui guardrails que a impedem de tomar a decisão final e que a palavra definitiva \"sempre será do humano\".\n\"A gente investe muito tempo e às vezes as conversas com as pessoas de feedback duram 15 minutos. Como fazer o processo de avaliação de desempenho ser mais rápido, ser mais eficiente, para que a gente possa investir mais tempo conversando com as pessoas e tendo conversas? Então nós criámos o Performa, mas ele não estava autorizado a definir a avaliação final das pessoas, porque, quando entra o aspecto de julgamento, a gente entende que julgamento ainda compete às pessoas\", afirma.\nPor fim, Abi-Saber traz que a ambição por escalabilidade e ROI não pode ocorrer em detrimento da segurança e que o QuintoAndar possui uma \"base robusta\" de cibersegurança para garantir a governança dos dados de seus 3 milhões de clientes. \"Hoje, há uma equipe de cibersegurança muito robusta e com mais de 13 anos de experiência em cibersegurança. A gente desenhou uma plataforma que já tem a confidencialidade dos clientes e a confiança de 3 milhões de clientes. Então, entendemos que estamos super bem posicionados, nós temos a segurança para conseguir colocar a IA e para ganhar escalabilidade e velocidade na solução dos problemas para os cliente\", conclui.","source_id":"tiinside","first_seen":"2026-06-19","pub_date":"2026-06-19"},{"title":"The Download: AI bottleneck debates, and BCI trials take off","title_pt":null,"url":"https://www.technologyreview.com/2026/06/19/1139327/the-download-llms-bottleneck-breakthrough-bci-trials-take-off/","summary":"This is today&#8217;s edition of The Download, our weekday newsletter that provides a daily dose of what&#8217;s going on in the world of technology. A startup claims it broke through a bottleneck that’s holding back LLMs AI startup Subquadratic came out of stealth last month with a huge claim: it had solved a mathematical bottleneck&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-19","pub_date":"2026-06-19"},{"title":"Adobe defende que marcas troquem volume por relevância e usem a criatividade para ganhar protagonismo na era da IA","title_pt":"Adobe defende que marcas troquem volume por relevância e usem a criatividade para ganhar protagonismo na era da IA","url":"https://tiinside.com.br/19/06/2026/adobe-defende-que-marcas-troquem-volume-por-relevancia-e-usem-a-criatividade-para-ganhar-protagonismo-na-era-da-ia/","summary":"A ascensão da inteligência artificial generativa mudou a forma como empresas se relacionam com consumidores, desenvolvem campanhas e medem resultados. Mas, ao contrário do que muitos imaginavam, a tecnologia não reduziu a importância da criatividade. Pelo contrário: ela elevou seu valor estratégico.","summary_pt":"A ascensão da inteligência artificial generativa mudou a forma como empresas se relacionam com consumidores, desenvolvem campanhas e medem resultados. Mas, ao contrário do que muitos imaginavam, a tecnologia não reduziu a importância da criatividade. Pelo contrário: ela elevou seu valor estratégico.\nEssa é a visão de Mari Pinudo, Country Manager da Adobe Brasil, compartilhada em entrevista à TI Inside. Para a executiva, a transformação em curso vai muito além da adoção de novas tecnologias: ela passa por uma mudança profunda na forma como as empresas compreendem seus consumidores, constroem relacionamentos e entregam experiências relevantes.\n\"Estamos vivendo uma mudança muito profunda em negócios, marketing, tecnologia e comportamento do consumidor. A inteligência artificial faz parte desse contexto, mas não é um tema isolado. Ela está inserida em toda essa transformação\", afirma.\nSegundo a executiva, o conceito de colocar o cliente no centro das estratégias não é novo. O que mudou foi a capacidade tecnológica de tornar essa promessa realidade.\n**Experiência em tempo real**\nPara Mari, a combinação entre dados, plataformas de experiência e inteligência artificial permite que empresas entreguem interações personalizadas em escala e em tempo real – algo que até poucos anos atrás era restrito a projetos pontuais.\n\"Hoje conseguimos capturar sinais dos consumidores e responder de forma muito mais rápida, relevante e eficiente. O cliente quer ser visto, ouvido e atendido de maneira personalizada\", explica.\nA mudança acontece em um contexto no qual consumidores convivem com múltiplas telas, canais e plataformas simultaneamente. Nesse ambiente, a disputa pela atenção se torna cada vez mais complexa.\nMas Mari faz uma ressalva importante: o objetivo das marcas não deve ser \"prender\" o consumidor. \"A questão não é manter a pessoa mais tempo com você. É tornar a experiência mais eficiente. Quanto mais rápido o consumidor encontra aquilo que procura e percebe valor na interação, maior a chance de conversão.\"\n**IA libera espaço para a criatividade**\nSe a automação assumiu tarefas operacionais, a criatividade passou a ocupar uma posição ainda mais estratégica dentro das empresas.\nSegundo a executiva, profissionais criativos historicamente gastavam grande parte do tempo executando processos burocráticos e transformando ideias em peças, campanhas e conteúdos. Hoje, a IA reduz significativamente esse esforço.\n\"A criatividade nunca foi tão importante. Agora ela não fica mais escondida atrás de tarefas operacionais. A tecnologia devolve tempo para que as pessoas possam pensar, criar e inovar.\"\nO mesmo movimento acontece nas áreas de marketing. Processos que antes demandavam semanas para serem executados e avaliados podem agora ser monitorados quase em tempo real.\n\"Se uma campanha está funcionando, você consegue escalar rapidamente. Se não está, consegue corrigir a rota. Isso libera espaço para o marketing focar mais em estratégia e criatividade\", explica.\n**O fim ...","source_id":"tiinside","first_seen":"2026-06-19","pub_date":"2026-06-19"},{"title":"A startup claims it broke through a bottleneck that’s holding back LLMs","title_pt":null,"url":"https://www.technologyreview.com/2026/06/19/1139313/a-startup-claims-it-broke-through-a-bottleneck-thats-holding-back-llms/","summary":"Miami-based AI startup Subquadratic came out of stealth mode last month with a huge claim. It announced that it had solved a mathematical bottleneck that had been holding back large language models for almost a decade. The details were thin, and many people were unconvinced. But Subquadratic has started to bring the receipts, sharing the&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-19","pub_date":"2026-06-19"},{"title":"What corporate leaders can learn from start-up founders","title_pt":null,"url":"https://www.mckinsey.com/capabilities/mckinsey-technology/our-insights/what-corporate-leaders-can-learn-from-start-up-founders","summary":"Alurx Founder and CEO Julia Stewart discusses her journey from public company CEO to health tech entrepreneur—and how corporate leaders can build confidence to transform their companies with AI.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-18","pub_date":"2026-06-18"},{"title":"Rewiring Talent to Value in the age of AI","title_pt":null,"url":"https://www.mckinsey.com/capabilities/people-and-organizational-performance/our-insights/rewiring-talent-to-value-in-the-age-of-ai","summary":"As humans enter a new era with AI agents as coworkers, companies need to update their framework for defining their most valuable roles. Here’s how to get started.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-19","pub_date":"2026-06-18"},{"title":"AI is turning every company into a software company","title_pt":null,"url":"https://www.mckinsey.com/capabilities/tech-and-ai/our-insights/ai-is-turning-every-company-into-a-software-company","summary":"As AI makes software faster and cheaper to build, the real competitive edge shifts to how it’s used—pushing leaders to rethink what work looks like and how teams spend their time.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-19","pub_date":"2026-06-18"},{"title":"Brilliant Moves: Coffee with FairPrice Group’s Vipul Chawla","title_pt":null,"url":"https://www.mckinsey.com/industries/consumer-packaged-goods/our-insights/brilliant-moves-coffee-with-fairprice-groups-vipul-chawla","summary":"FairPrice Group’s Vipul Chawla chats with McKinsey’s Gautam Kumra about using AI to remove friction from shopping, navigating supply chain shocks, and balancing innovation with the mission to keep daily essentials affordable.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-19","pub_date":"2026-06-18"},{"title":"The rise of the agentic shopper: ASOS’s AI investment","title_pt":null,"url":"https://www.mckinsey.com/industries/retail/our-insights/the-rise-of-the-agentic-shopper-asoss-ai-investment","summary":"The British fashion retailer’s chief technology officer discusses why agentic AI represents ‘a structural shift’ in how consumers engage with brands.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-18","pub_date":"2026-06-18"},{"title":"The turning point for real-world robotics","title_pt":null,"url":"https://www.mckinsey.com/industries/industrials/our-insights/the-turning-point-for-real-world-robotics","summary":"Daniela Rus, director of MIT’s Computer Science and Artificial Intelligence Laboratory, shares a vision for robots that learn faster, respond in real time, and fit naturally into our lives.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-18","pub_date":"2026-06-17"},{"title":"Prompt Hungary: The impact of AI on the competitiveness of the economy","title_pt":null,"url":"https://www.mckinsey.com/capabilities/quantumblack/our-insights/prompt-hungary-the-impact-of-ai-on-the-competitiveness-of-the-economy","summary":"AI could become a powerful growth engine for the country by helping overcome the economy’s challenges and limitations, and generating improved productivity and lasting competitive advantage.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-16","pub_date":"2026-06-16"},{"title":"The symbiotic enterprise","title_pt":null,"url":"https://www.mckinsey.com/capabilities/quantumblack/our-insights/the-symbiotic-enterprise","summary":"How cognitive and physical AI are reinventing enterprise execution","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-17","pub_date":"2026-06-16"},{"title":"Exclusive eBook: How AI is becoming the next military advisor","title_pt":null,"url":"https://www.technologyreview.com/2026/06/16/1138905/exclusive-ebook-how-ai-is-becoming-the-next-military-advisor/","summary":"A collection of stories about how militaries are using AI models to make decisions. This subscriber-only eBook is a package of six stories that were originally published in MIT Technology Review between April 11, 2025, and April 21, 2026, and have been updated to reflect recent developments. by James O&#8217;Donnell Choose which file format to&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-17","pub_date":"2026-06-16"},{"title":"The agentic advertising economy: From attention to action","title_pt":null,"url":"https://www.mckinsey.com/industries/technology-media-and-telecommunications/our-insights/the-agentic-advertising-economy-from-attention-to-action","summary":"As AI changes how consumers discover products and impact is measured, advertising value will shift to the players that can shape what is seen, selected, and purchased.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-16","pub_date":"2026-06-16"},{"title":"The Download: the first brain implant power user and South Korea’s AI obsession","title_pt":null,"url":"https://www.technologyreview.com/2026/06/16/1139010/the-download-brain-implant-power-user-bci-south-korea-ai-obsession/","summary":"This is today&#8217;s edition of The Download, our weekday newsletter that provides a daily dose of what&#8217;s going on in the world of technology. This man with ALS is the first “power user” of a brain implant that lets him speak Casey Harrell has had a set of electrodes embedded in his brain for almost&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-16","pub_date":"2026-06-16"},{"title":"Why do South Koreans love AI so much?","title_pt":null,"url":"https://www.technologyreview.com/2026/06/15/1138983/why-do-south-koreans-love-ai-so-much/","summary":"This story originally appeared in The Algorithm, our weekly newsletter on AI. To get stories like this in your inbox first,&#160;sign up here. When I landed in Seoul after a grueling 12-hour flight from San Francisco, I walked through an unmanned immigration checkpoint, where a machine scanned my face and passport. On the subway home,&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-16","pub_date":"2026-06-15"},{"title":"Do prompt ao resultado: Como os Agentes de IA estão eliminando o trabalho burocrático das equipes comerciais B2B","title_pt":"Do prompt ao resultado: Como os Agentes de IA estão eliminando o trabalho burocrático das equipes comerciais B2B","url":"https://tiinside.com.br/15/06/2026/do-prompt-ao-resultado-como-os-agentes-de-ia-estao-eliminando-o-trabalho-burocratico-das-equipes-comerciais-b2b/","summary":"Você já parou para calcular quantas horas sua equipe comercial perde com planilhas, atualizações manuais de CRM e pesquisas intermináveis sobre prospects?","summary_pt":"Você já parou para calcular quantas horas sua equipe comercial perde com planilhas, atualizações manuais de CRM e pesquisas intermináveis sobre prospects?\nA maioria das vezes comerciais ainda usa inteligência artificial de forma limitada: gerar um texto de proposta aqui, escrever um e-mail ali. Mas o potencial vai muito além disso. Estamos falando de agentes de IA independentes — sistemas que analisam dados, executam tarefas comerciais, aprendem com o uso e tomam decisões baseadas em critérios que evoluem com o tempo.\nComo explica o Agente, esses agentes estão em um patamar completamente diferente dos chatbots engessados ??que muitos ainda associam à IA.\nA pergunta não é mais _se_ esses agentes vão transformar a rotina comercial. São _quais etapas_ eles vão automatizar primeiro — e como você pode se preparar.\n**Como identificamos as etapas de automação prioritárias**\nPara mapear onde os agentes de IA geram mais impacto, estabelecemos cinco critérios de avaliação: volume de trabalho burocrático envolvido, atualização tecnológica das soluções disponíveis, impacto mensurável sobre receita e produtividade, complexidade de implementação e, principalmente, a demanda real dos próprios vendedores.\nO foco aqui são equipes comerciais B2B com processos consultivos — aquelas que operam divididas entre CRM, Excel, WhatsApp e diversas ferramentas que não conversam entre si.\nO Panorama do uso de Inteligência Artificial nas Vendas B2B no Brasil 2025, programado pelo Agente com 1.031 profissionais, revela exatamente onde estão as dores e os desejos de automação. Combinamos esses dados com pesquisas globais de Salesforce, BCG, Gartner, McKinsey e casos práticos de plataformas como o [Genspark IA](https://www.genspark.ai/pt) .\nO resultado? Seis etapas em que os agentes de IA já estão eliminando o trabalho burocrático — e liberando vendedores para o que realmente importa.\n**Etapa 1 — Pesquisa de mercado e prospecção inteligente**\nA geração de leads é o calcanhar de Aquiles das equipes B2B brasileiras. O Panorama Agendador 2025 aponta que 26,74% dos profissionais citam esse como seu maior desafio — o topo da lista, à frente até da conversão de oportunidades.\nO que torna essa etapa tão desastrosa? Um manual de pesquisa. O vendedor abre o LinkedIn, vasculha o site da empresa, busca notícias recentes, tenta entender o momento do prospect. Uma hora depois, preenchau cinco campos no CRM. Agora multiplique isso por ofertas de leads por semana.\nÉ aqui que os agentes autônomos mudam completamente o jogo. O Genspark AI Workspace 4.0 dinâmico o Genspark Claw, um agente que combina operação de arquivos locais com navegação web automática. Na prática, ele pesquisa vários sites, extrai dados relevantes, preenche formulários e alimenta o CRM com informações estruturadas sobre cada prospect — tudo de forma independente, sem intervenção humana.\nOs números confirmam a tendência. Uma pesquisa InfoMoney revela que [37,92% dos vendedores brasileiros já usam IA para pesquisar prospect...","source_id":"tiinside","first_seen":"2026-06-15","pub_date":"2026-06-15"},{"title":"The health system CEO imperative: Turning AI’s promise into performance","title_pt":null,"url":"https://www.mckinsey.com/industries/healthcare/our-insights/the-health-system-ceo-imperative-turning-ais-promise-into-performance","summary":"Health systems aren’t short on AI, they’re short on impact from AI. Capturing real value requires CEO-led transformation and a fundamental rethink of how care and operations run.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-15","pub_date":"2026-06-15"},{"title":"Elevating the customer experience: IKEA’s agentic AI journey","title_pt":null,"url":"https://www.mckinsey.com/industries/retail/our-insights/elevating-the-customer-experience-ikeas-agentic-ai-journey","summary":"The Swedish home-furnishing giant’s chief digital officer discusses the need to prioritize AI initiatives amid ‘the risk of doing everything but maybe nothing.’","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-11","pub_date":"2026-06-11"},{"title":"Google DeepMind is worried about what happens when millions of agents start to interact","title_pt":null,"url":"https://www.technologyreview.com/2026/06/11/1138794/google-deepmind-is-worried-about-what-happens-when-millions-of-agents-start-to-interact/","summary":"Google DeepMind is funding research into the potential dangers of situations where millions of different AI agents interact with each other online. According to Rohin Shah, who directs the company’s AGI safety and alignment research, the mass-market arrival of agents that can carry out tasks without human oversight and follow instructions given to them by other&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-11","pub_date":"2026-06-11"},{"title":"The seven operating truths of AI-native companies","title_pt":null,"url":"https://www.mckinsey.com/capabilities/business-building/our-insights/the-seven-operating-truths-of-ai-native-companies","summary":"Almost every company has AI tools, but few really know how to use them. Leaders at 15 AI-savvy companies say the difference comes down to seven operating truths—that most organizations still get wrong.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-12","pub_date":"2026-06-11"},{"title":"Rewiring retail in Europe: The AI imperative","title_pt":null,"url":"https://www.mckinsey.com/industries/retail/our-insights/rewiring-retail-in-europe-the-ai-imperative","summary":"AI is already reshaping the European retail value chain. The question now is how leaders modernize while strengthening the human experience—with a €240 billion to €320 billion opportunity at stake.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-10","pub_date":"2026-06-10"},{"title":"Europe’s new e‑commerce agenda: How AI is resetting growth and competition","title_pt":null,"url":"https://www.mckinsey.com/capabilities/growth-marketing-and-sales/our-insights/europes-new-ecommerce-agenda-how-ai-is-resetting-growth-and-competition","summary":"From agentic shopping to retail media and omnichannel intelligence, AI is changing the economics of digital commerce. Here’s how leaders can turn experimentation into a durable advantage.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-10","pub_date":"2026-06-10"},{"title":"A próxima revolução da IA será baseada na capacidade de compartilhar inteligência em escala","title_pt":"A próxima revolução da IA será baseada na capacidade de compartilhar inteligência em escala","url":"https://tiinside.com.br/10/06/2026/a-proxima-revolucao-da-ia-sera-baseada-na-capacidade-de-compartilhar-inteligencia-em-escala/","summary":"Durante décadas, empresas investiram bilhões de dólares para integrar sistemas, consolidar bases de dados e construir plataformas capazes de oferecer uma visão única do negócio. Para Thiago Oliveira, CIO Global da Coca-Cola FEMSA, esse movimento foi fundamental, mas já não é suficiente para responder aos desafios atuais.","summary_pt":"Durante décadas, empresas investiram bilhões de dólares para integrar sistemas, consolidar bases de dados e construir plataformas capazes de oferecer uma visão única do negócio. Para Thiago Oliveira, CIO Global da Coca-Cola FEMSA, esse movimento foi fundamental, mas já não é suficiente para responder aos desafios atuais.\nEm sua apresentação durante evento Deloitte Latam ConnecT Mexico 2026, frente a um publico concentrado em CEOs, CIOs e CFOs de grandes corporações latino-americanas, o executivo provocou a audiência ao afirmar que a próxima transformação tecnológica não será impulsionada apenas pelos dados em si, mas pela capacidade das organizações de criar inteligências capazes de aprender, evoluir e agir.\n\"Passamos anos e milhões de dólares tentando conectar dados. E quando finalmente estamos chegando lá….o mundo mudou novamente\", afirmou.\nSegundo Oliveira, as empresas passaram boa parte dos últimos anos discutindo Data Lakes, MDMs, pipelines, ETL, governança e integração de dados. No entanto, a simples disponibilidade da informação, por si só, nunca foi suficiente para transformar decisões ou alterar a forma como as organizações operam. \"Os dados sozinhos nunca transformaram decisões ou ações\", comenta.\nNa visão do executivo, a mudança ocorre quando a inteligência gerada através do estudo dos dados deixa de estar presa aos sistemas e passa a ser incorporada aos próprios processos de negócio.\n**A inteligência artificial como reflexo da evolução humana**\nUm dos pontos mais originais da apresentação foi a comparação entre a evolução dos agentes de inteligência artificial e o desenvolvimento cognitivo humano.\nOliveira utilizou conceitos da neurociência, como Freud, Piaget e Carl Young para explicar como a construção da inteligência acontece em camadas sucessivas, desde a formação da identidade até a capacidade de tomar decisões complexas.\nSegundo ele, a adolescência representa um período particularmente interessante para compreender esse fenômeno. \"Segundo grandes pesquisadores de neurociência, como Piaget, Erik Erikson e Carl Young, entre os 12 e os 18 anos o cérebro atravessa sua fase mais rica de reestruturação. O córtex pré-frontal está sendo reconstruído. É ali que a arquitetura do pensamento ganha forma.\"\nNa avaliação do executivo, o mesmo processo pode ser observado na evolução dos agentes. \"Sobre a arquitetura da mente, cada fase mencionado aqui, corresponde a um momento real da sua vida, o momento em que você parou de absorver o mundo e começou a interpretá-lo, o momento em que você deixou de reproduzir padrões e começou a formar julgamentos. O que estou dizendo é que os agentes de IA estão passando pela mesma jornada. Só que em velocidade industrial\"\nAssim como ocorre com as pessoas, os agentes passam por diferentes estágios de desenvolvimento até adquirirem autonomia. Primeiro surge o modelo fundacional. Depois vêm o conhecimento especializado, o raciocínio, a memória construída a partir das interações e, finalmente, a autonomia.\n\"E...","source_id":"tiinside","first_seen":"2026-06-10","pub_date":"2026-06-10"},{"title":"AI usage among white-collar workers and students in Hong Kong: survey findings","title_pt":null,"url":"https://www.mckinsey.com/cn/updates/ai-usage-among-white-collar-workers-and-students-in-hong-kong-survey-findings","summary":"","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-10","pub_date":"2026-06-10"},{"title":"The Download: whole-body rejuvenation drugs and five things to know about AI","title_pt":null,"url":"https://www.technologyreview.com/2026/06/09/1138604/the-download-anti-aging-drugs-ai-five-things-to-know/","summary":"This is today&#8217;s edition of The Download, our weekday newsletter that provides a daily dose of what&#8217;s going on in the world of technology. David Sinclair plans to test whole-body rejuvenation drugs in the XPrize competition The outspoken longevity scientist David Sinclair has predicted that, one day, you’ll go to the doctor and get a&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-09","pub_date":"2026-06-09"},{"title":"Five things you need to know about AI","title_pt":null,"url":"https://www.technologyreview.com/2026/06/09/1138582/five-things-you-need-to-know-about-ai/","summary":"At SXSW London last week I gave a talk called “Five things you need to know about AI,” in which I shared what I think are the biggest themes in AI right now. I pulled a few things from our first AI10 list, an annual guide to the most important trends in this buzzy world,&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-09","pub_date":"2026-06-09"},{"title":"AI in life sciences explained: The technology that could reinvent medicine","title_pt":null,"url":"https://www.mckinsey.com/featured-insights/mckinsey-explainers/ai-in-life-sciences-explained-the-technology-that-could-reinvent-medicine","summary":"Three McKinsey experts explain how AI is reshaping life sciences—where it’s creating value today, why so many efforts stall, and what the next decade could mean for patients.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-10","pub_date":"2026-06-09"},{"title":"Learning to lead in a hybrid human-AI enterprise","title_pt":null,"url":"https://www.technologyreview.com/2026/06/09/1137830/learning-to-lead-in-a-hybrid-human-ai-enterprise/","summary":"As adoption of AI agents looks set to surge by as much as 300% in the next two years, leadership teams are carefully considering the implications of a hybrid human-AI workforce.  Unlike existing enterprise-level automation that relies on manual input, AI agents are capable of autonomously coordinating complex tasks, interacting with multiple tools and environments across&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-09","pub_date":"2026-06-09"},{"title":"Where value is won and lost in distribution","title_pt":null,"url":"https://www.mckinsey.com/industries/industrials/our-insights/where-value-is-won-and-lost-in-distribution","summary":"The state of distribution in the United States is defined by permanent volatility, especially from the emergence of AI. The ability to address five current themes will define leaders in this new era.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-10","pub_date":"2026-06-09"},{"title":"Reinventing autonomous driving in the age of generative AI","title_pt":null,"url":"https://www.mckinsey.com/industries/automotive-and-assembly/our-insights/reinventing-autonomous-driving-in-the-age-of-generative-ai","summary":"As AI-native systems take hold, autonomous driving is becoming a race for compute power, software, data, and semiconductors.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-10","pub_date":"2026-06-09"},{"title":"Blackstone’s Legal & Compliance AI transformation started with technology. It succeeded because it put people first","title_pt":null,"url":"https://www.mckinsey.com/capabilities/people-and-organizational-performance/how-we-help-clients/blackstones-legal-and-compliance-ai-transformation-started-with-technology","summary":"By first redesigning how decisions flow—clarifying ownership and codifying precedent—the financial services firm was able to rewire its Legal & Compliance group with technology at the core.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-09","pub_date":"2026-06-08"},{"title":"The Download: how the World Cup ball will fly and OpenAI’s “super app”","title_pt":null,"url":"https://www.technologyreview.com/2026/06/08/1138485/the-download-world-cup-ball-openai-super-app/","summary":"This is today&#8217;s edition of The Download, our weekday newsletter that provides a daily dose of what&#8217;s going on in the world of technology. Why this year’s World Cup ball may not fly as far Much is new about this month’s FIFA World Cup tournament. It hosts more teams than ever before. It’s the first&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-08","pub_date":"2026-06-08"},{"title":"Banking and AI: When the tech starts doing the work, not just assisting it","title_pt":null,"url":"https://www.mckinsey.com/featured-insights/mckinsey-explainers/banking-and-ai-when-the-tech-starts-doing-the-work-not-just-assisting-it","summary":"Three McKinsey experts explain how AI is reshaping banking from the inside out—and why the biggest obstacle isn’t the technology.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-08","pub_date":"2026-06-08"},{"title":"Reimagining federal procurement in the digital and AI age","title_pt":null,"url":"https://www.mckinsey.com/industries/public-sector/our-insights/reimagining-federal-procurement-in-the-digital-and-ai-age","summary":"Digitalizing federal procurement can improve decision-making, increase efficiency and transparency, and bolster resilience—all of which are critical in today’s high-pressure environment.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-08","pub_date":"2026-06-08"},{"title":"Inspira leva IA jurídica a escritórios e advogados autônomos","title_pt":"Inspira leva IA jurídica a escritórios e advogados autônomos","url":"https://tiinside.com.br/05/06/2026/inspira-leva-ia-juridica-a-escritorios-e-advogados-autonomos/","summary":"A transformação digital do setor jurídico ganha um novo capítulo com o avanço das plataformas de inteligência artificial especializadas. Em um mercado que busca equilibrar produtividade, segurança de dados e qualidade técnica, a legaltech Inspira anunciou o lançamento de três novas soluções que ampliam sua plataforma de IA jurídica e consolidam um ecossistema integrado para escritórios de advoc...","summary_pt":"A transformação digital do setor jurídico ganha um novo capítulo com o avanço das plataformas de inteligência artificial especializadas. Em um mercado que busca equilibrar produtividade, segurança de dados e qualidade técnica, a legaltech Inspira anunciou o lançamento de três novas soluções que ampliam sua plataforma de IA jurídica e consolidam um ecossistema integrado para escritórios de advocacia, departamentos jurídicos corporativos e profissionais autônomos.\nA iniciativa ocorre em um momento de crescente adoção de inteligência artificial pelo setor. Segundo estimativas do Goldman Sachs, cerca de 80% das tarefas jurídicas rotineiras podem ser automatizadas com o apoio da tecnologia. Já o Estudo Demográfico da Advocacia Brasileira, realizado pela FGV em 2024, aponta que 95% dos profissionais do Direito reconhecem que as ferramentas tecnológicas contribuem para aumentar a eficiência do trabalho jurídico.\nAs novidades apresentadas pela Inspira incluem o Chat, o Agente e o Acervo, soluções desenvolvidas para centralizar atividades jurídicas em uma única plataforma e reduzir a dependência de aplicações genéricas de IA, frequentemente utilizadas sem controles específicos para proteção de informações sensíveis.\nO Chat funciona como uma interface de linguagem natural voltada para consultas jurídicas, análise documental e elaboração de peças processuais. A proposta é permitir que advogados realizem pesquisas e produzam conteúdo com referências verificáveis dentro de um ambiente controlado, sem a necessidade de transferir documentos para plataformas externas.\nJá o Agente foi projetado para executar tarefas mais complexas e de maior duração. A ferramenta cria um plano de trabalho que pode ser validado pelo profissional e, posteriormente, realiza as atividades em segundo plano, permitindo que o usuário mantenha o foco em demandas estratégicas enquanto a IA conduz etapas operacionais.\nO terceiro lançamento, denominado Acervo, aplica inteligência artificial à gestão do conhecimento jurídico. A solução transforma bibliotecas digitais, regulamentos, manuais internos, livros e bases documentais em um ambiente pesquisável por IA, entregando respostas acompanhadas de referências completas, incluindo autor, obra e página de origem.\nSegundo Rafael Grimaldi, cofundador e CEO da Inspira, o objetivo é ampliar o acesso à tecnologia especializada e oferecer uma alternativa segura às ferramentas de IA de uso geral. De acordo com o executivo, a plataforma foi desenvolvida para atender aos requisitos de confidencialidade exigidos pela advocacia e permitir que profissionais de diferentes portes tenham acesso à mesma infraestrutura tecnológica utilizada por grandes organizações.\nA expansão representa também uma mudança estratégica para a empresa. Tradicionalmente voltada para escritórios de médio e grande porte e departamentos jurídicos corporativos, a Inspira passa agora a oferecer sua infraestrutura para advogados autônomos, ampliando sua atuação no segmento B2C.\nA com...","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-05"},{"title":"The Download: AI hacking beyond Mythos, and chatbots’ impact on our brains","title_pt":null,"url":"https://www.technologyreview.com/2026/06/05/1138452/the-download-ai-hacking-mythos-chatbots-brain-impacts/","summary":"This is today&#8217;s edition of The Download, our weekday newsletter that provides a daily dose of what&#8217;s going on in the world of technology. The Meta hack shows there’s more to AI security than Mythos On Monday, reports emerged that attackers had used Meta’s AI customer support agent to steal Instagram accounts. Their approach was&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-05","pub_date":"2026-06-05"},{"title":"Are AI chatbots making us lose control of our brains?","title_pt":null,"url":"https://www.technologyreview.com/2026/06/05/1138427/are-ai-chatbots-making-us-lose-control-of-our-brains/","summary":"This week I’ve been at SXSW London. There’s been music, film, and a lot—and I mean a lot—of talk about AI. I also had the opportunity to sit down with Gloria Mark, a psychologist at the University of California, Irvine, who has spent the last 30 years studying how people interact with digital technologies. Early&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-05","pub_date":"2026-06-05"},{"title":"Resetting cost competitiveness in pulp and paper packaging","title_pt":null,"url":"https://www.mckinsey.com/industries/packaging-and-paper/our-insights/resetting-cost-competitiveness-in-pulp-and-paper-packaging","summary":"Overcapacity, volatile costs, and weak demand are compressing margins. Successful companies are harnessing AI to pursue cross-functional interventions that target the total cost baseline of a mill.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-05","pub_date":"2026-06-05"},{"title":"Reforma Tributária: sua empresa está pronta para os impactos no RH e na Folha de Pagamento?","title_pt":"Reforma Tributária: sua empresa está pronta para os impactos no RH e na Folha de Pagamento?","url":"https://tiinside.com.br/05/06/2026/reforma-tributaria-sua-empresa-esta-pronta-para-os-impactos-no-rh-e-na-folha-de-pagamento/","summary":"A Reforma Tributária já está em andamento e seus impactos vão muito além das áreas fiscal e contábil. RH, Folha de Pagamento, Finanças e Tecnologia terão papel fundamental para garantir que as empresas se adaptem às novas exigências com segurança, eficiência e conformidade.","summary_pt":"A Reforma Tributária já está em andamento e seus impactos vão muito além das áreas fiscal e contábil. RH, Folha de Pagamento, Finanças e Tecnologia terão papel fundamental para garantir que as empresas se adaptem às novas exigências com segurança, eficiência e conformidade.\nMas sua organização está preparada para essa transformação?\nPara ajudar empresas a entenderem os desafios e oportunidades desse novo cenário, a TI Inside e a ADP promovem  dia 23 de junho, o webinar gratuito \" **Da Reforma à Transformação: Como preparar o RH e a Folha para o novo cenário tributário no Brasil\".**\nDurante o encontro, especialistas do mercado vão mostrar como a Reforma Tributária pode se tornar um catalisador para a modernização dos processos de RH e da gestão da folha de pagamento, impulsionando ganhos de produtividade, automação, governança e redução de riscos operacionais.\n- Como a Reforma Tributária impacta as áreas de RH, Folha e Finanças;\n- Quais mudanças exigirão maior atenção das empresas nos próximos anos;\n- Como a automação pode reduzir erros, retrabalho e custos operacionais;\n- Os benefícios da terceirização da folha em um ambiente regulatório cada vez mais complexo;\n- Como garantir compliance, padronização e previsibilidade em um cenário de constantes mudanças;\n- O papel da tecnologia na construção de operações mais escaláveis e eficientes.\nEste é um momento decisivo para as organizações que desejam transformar obrigações regulatórias em vantagem competitiva. Participar deste webinar é uma oportunidade para antecipar tendências, esclarecer dúvidas e conhecer estratégias práticas para preparar sua empresa para o futuro.\n**Palestrantes confirmados:**\n- Alexandre Moro – Senior Latam Director Field Sales da ADP\n- Armando Silva – Senior Director Accounting da ADP\n- Cássia Paixão – Especialista Tributária da Qyon Tecnologia\n- Claudiney Santos – Editor da TI Inside (mediador)","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-05"},{"title":"Programa nacional vai formar até 180 pesquisadores em IA para a indústria","title_pt":"Programa nacional vai formar até 180 pesquisadores em IA para a indústria","url":"https://tiinside.com.br/05/06/2026/programa-nacional-vai-formar-ate-180-pesquisadores-em-ia-para-a-industria/","summary":"Em um cenário de crescente demanda por especialistas em Inteligência Artificial no Brasil, o edital do programa Industr.IA foi lançado oficialmente ontem, 02 de junho, com a proposta de formar pesquisadores e fortalecer a pesquisa aplicada em Tecnologia da Informação e Comunicação (TIC) voltada à indústria nacional.","summary_pt":"Em um cenário de crescente demanda por especialistas em Inteligência Artificial no Brasil, o edital do programa Industr.IA foi lançado oficialmente ontem, 02 de junho, com a proposta de formar pesquisadores e fortalecer a pesquisa aplicada em Tecnologia da Informação e Comunicação (TIC) voltada à indústria nacional.\nA iniciativa, executada pelo Instituto Atlântico, por meio da Escola Atlântico Avanti, e pelo iRede em parceria com universidades brasileiras, prevê investimento de aproximadamente R$ 46 milhões ao longo de quatro anos. O programa prevê a capacitação de 130 a 180 pesquisadores, além da criação de pelo menos 15 núcleos de pesquisa em Inteligência Artificial em diferentes regiões do país e é apoiado com recursos da Lei nº 8.248/1991.\nO programa também prevê o desenvolvimento de cerca de 90 produtos científicos e tecnológicos, entre artigos, softwares e patentes, ampliando a conexão entre universidades, indústria e pesquisa aplicada.\nO Industr.IA tem coordenação estratégica da Softex no âmbito das diretrizes do Comitê da Área de Tecnologia da Informação (CATI) para capacitação em TIC. A iniciativa está alinhada ao Plano Brasileiro de Inteligência Artificial (PBIA 2024), ao programa IA² MCTI, ao \"MCTI Futuro do Trabalho\" e à Lei da Informática (Lei nº 8.248/91).\n\"O Brasil vive uma corrida pela formação de talentos em IA. A indústria precisa de profissionais capazes de transformar pesquisa em inovação aplicada e ganho de competitividade\", afirma Cleilton Rocha, líder de IA e Ciência de Dados do Atlântico.\nO Industr.IA atuará em áreas estratégicas como IA Generativa, modelos de linguagem (LLMs), Visão Computacional, Machine Learning, Deep Learning, Engenharia de Dados e Edge AI, tecnologias utilizadas em automação industrial, análise inteligente de dados e desenvolvimento de soluções avançadas de inteligência artificial.\nSegundo Cleilton Rocha, o programa busca aproximar formação acadêmica e demandas reais do setor produtivo. \"A inteligência artificial deixou de ser tendência e passou a ser uma necessidade estratégica para a competitividade industrial. O objetivo é formar pesquisadores preparados para atuar em desafios concretos da indústria brasileira\", destaca.","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-05"},{"title":"The Meta hack shows there’s more to AI security than Mythos","title_pt":null,"url":"https://www.technologyreview.com/2026/06/05/1138437/the-meta-hack-shows-theres-more-to-ai-security-than-mythos/","summary":"On June 5, 404 Media reported that attackers had been using Meta’s AI customer support agent to steal Instagram accounts. Their approach was simple: They asked the agent to link the accounts to email addresses that they controlled, and the agent complied. One attacker broke into the dormant Obama White House account and made pro-Iran&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-05","pub_date":"2026-06-05"},{"title":"Preparing for agentic commerce: REWE’s AI transformation","title_pt":null,"url":"https://www.mckinsey.com/industries/retail/our-insights/preparing-for-agentic-commerce-rewes-ai-transformation","summary":"The German retail and tourism group’s chief digital and technology officer says AI is “the most fundamental change in the way we do business in 50 years.”","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-05","pub_date":"2026-06-04"},{"title":"The Download: AI-generated lawsuits and virtual power plants for data centers","title_pt":null,"url":"https://www.technologyreview.com/2026/06/04/1138408/the-download-ai-lawsuits-virtual-power-plants-data-centers/","summary":"This is today&#8217;s edition of The Download, our weekday newsletter that provides a daily dose of what&#8217;s going on in the world of technology. How courts are coping with a flood of AI-generated lawsuits Most days in her chambers, Judge Maritza Braswell, a federal magistrate judge in Colorado, sifts through stacks of documents written by&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-04","pub_date":"2026-06-04"},{"title":"Embracing complexity: Parloa’s vision for next-gen customer experience","title_pt":null,"url":"https://www.mckinsey.com/capabilities/operations/our-insights/embracing-complexity-parloas-vision-for-next-gen-customer-experience","summary":"Chris Silver, chief revenue officer at Parloa, talks with McKinsey partner Brian Blackader about the shift to adopting AI technologies in customer care, getting to success, and how he sees the future.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-05","pub_date":"2026-06-04"},{"title":"How courts are coping with a flood of AI-generated lawsuits","title_pt":null,"url":"https://www.technologyreview.com/2026/06/04/1138391/courts-coping-ai-lawsuits/","summary":"Most days in her chambers, Judge Maritza Braswell, a federal magistrate judge in Colorado, sifts through stacks of documents written by people without a lawyer. Many of them can’t afford to hire a lawyer, and others have cases too weak or too small to interest one. She reads each one carefully, mindful of how daunting&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-04","pub_date":"2026-06-04"},{"title":"How CEOs can navigate the new era of trade","title_pt":null,"url":"https://www.mckinsey.com/mgi/our-research/how-ceos-can-navigate-the-new-era-of-trade","summary":"AI, geopolitical realignment, and shifting capital flows are redrawing trade corridors and reshaping competitive advantage—forcing leaders to rethink where and how they grow.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-05","pub_date":"2026-06-04"},{"title":"Apps de IA já estão presentes em 38,9% dos celulares brasileiros","title_pt":"Apps de IA já estão presentes em 38,9% dos celulares brasileiros","url":"https://tiinside.com.br/03/06/2026/apps-de-ia-ja-estao-presentes-em-389-dos-celulares-brasileiros/","summary":"Um estudo realizado pela Mintech, datatech especializada na coleta, tratamento e modelagem de dados extraídos diretamente de smartphones, revela que 38,9% dos telefones celulares brasileiros já possuem pelo menos um aplicativo dedicado à Inteligência Artificial (IA) instalado e em uso potencial pelos consumidores. O levantamento analisou uma base composta por 1 milhão de smartphones em março e ...","summary_pt":"Um estudo realizado pela Mintech, datatech especializada na coleta, tratamento e modelagem de dados extraídos diretamente de smartphones, revela que 38,9% dos telefones celulares brasileiros já possuem pelo menos um aplicativo dedicado à Inteligência Artificial (IA) instalado e em uso potencial pelos consumidores. O levantamento analisou uma base composta por 1 milhão de smartphones em março e identificou a presença desse tipo de aplicação em 389.865 aparelhos.\nPara o CEO da Mintech, Gustavo Cruz, os resultados da pesquisa sinalizam que o Brasil está acompanhando o que tem se demonstrado uma tendência mundial em relação ao uso de IA. \"Os números comprovam que a adoção da IA deixou de ser uma prática restrita ao ambiente corporativo e passou a ocupar espaço relevante no cotidiano digital da população\", diz.\nEle argumenta que o resultado acompanha um movimento observado em diferentes mercados globais que é a rápida incorporação de ferramentas generativas e assistentes inteligentes diretamente nos dispositivos móveis. \"Em um cenário internacional marcado pela popularização de modelos de IA e pela disputa por presença no ecossistema digital, o smartphone se consolida como principal ponto de contato entre usuários e novas tecnologias\", diz.\nEntre as aplicações mais recorrentes detectadas pela Mintech, cinco marcas concentram grande parte do uso dos brasileiros. O ChatGPT aparece na liderança, presente em 23,7% dos celulares analisados, seguido por Gemini (8%), Copilot (1,6%), DeepSeek (0,8%) e Grok (0,6%). Também aparecem no ranking aplicativos como Bard, Claude, Codex, Grok Beta, Grok Beta Premium, Manus e Perplexity.\nSegundo os responsáveis pelo trabalho, a predominância dos assistentes conversacionais e das soluções de IA generativa reforça outra tendência mundial: a transformação da interação digital por meio de interfaces mais naturais, orientadas por linguagem e cada vez mais integradas à rotina de trabalho, estudo, consumo e busca por informação.\n\"À medida que mais usuários incorporam IA ao celular, cresce também a demanda por serviços personalizados, experiências automatizadas e modelos capazes de transformar dados em respostas e decisões em tempo real\", afirma Cruz. \"Os números mostram que o Brasil já participa ativamente desse ciclo de adoção global e reforçam o papel dos dispositivos móveis como um dos principais vetores de disseminação da inteligência artificial nos próximos anos\", conclui.","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-03"},{"title":"The Download: Trump’s new AI order, and smart glasses for warfare","title_pt":null,"url":"https://www.technologyreview.com/2026/06/03/1138322/the-download-trump-ai-order-smart-glasses-warfare/","summary":"This is today&#8217;s edition of The Download, our weekday newsletter that provides a daily dose of what&#8217;s going on in the world of technology. 5 key points in Trump&#8217;s new AI order Less than two weeks after scrapping an executive order on AI, President Donald Trump signed a new one on Tuesday. Promising to promote&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-03","pub_date":"2026-06-03"},{"title":"Como agentes de IA estão redefinindo o desenvolvimento de produtos e software no Itaú","title_pt":"Como agentes de IA estão redefinindo o desenvolvimento de produtos e software no Itaú","url":"https://tiinside.com.br/03/06/2026/como-agentes-de-ia-estao-redefinindo-o-desenvolvimento-de-produtos-e-software-no-itau/","summary":"Bem-vindo! Entre na sua conta","summary_pt":"Bem-vindo! Entre na sua conta\nUma senha será enviada por e-mail para você.\n### [Relatório do Impacto dos Dados e da IA: Mergulhe na pesquisa](https://www.sas.com/pt_br/gc/data-and-ai-impact-report.html\\#download\\#new_tab \"Relatório do Impacto dos Dados e da IA: Mergulhe na pesquisa\")\n- INTELIGÊNCIA ARTIFICIAL","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-03"},{"title":"Vero amplia aposta na convergência, expande estratégia móvel e lança novo portfólio de serviços","title_pt":"Vero amplia aposta na convergência, expande estratégia móvel e lança novo portfólio de serviços","url":"https://tiinside.com.br/03/06/2026/vero-amplia-aposta-na-convergencia-expande-estrategia-movel-e-lanca-novo-portfolio-de-servicos/","summary":"A Vero, uma das principais empresas de telecomunicações do país, inicia uma nova etapa da sua estratégia de negócios ao ampliar sua aposta na convergência e na expansão do móvel, que se consolida como um dos principais vetores de crescimento da companhia. A empresa passa a comercializar o serviço móvel de forma independente, sem a necessidade de contratação da banda larga fixa. ao mesmo tempo e...","summary_pt":"A Vero, uma das principais empresas de telecomunicações do país, inicia uma nova etapa da sua estratégia de negócios ao ampliar sua aposta na convergência e na expansão do móvel, que se consolida como um dos principais vetores de crescimento da companhia. A empresa passa a comercializar o serviço móvel de forma independente, sem a necessidade de contratação da banda larga fixa. ao mesmo tempo em que lança um novo portfólio de soluções para consumidores e empresas.\nPara sustentar este novo ciclo, a Vero investirá aproximadamente R$ 110 milhões em até três anos, voltados para iniciativas como pesquisa e desenvolvimento de produtos, adaptações sistêmicas nos ERPs, core de rede, investimento em pessoal, adaptações na logística de chips, entre outras.\nO lançamento do Vero Controle Mais, oferta que combina o serviço móvel e conteúdos, permite que a companhia amplie significativamente seu mercado endereçável, para além da base tradicional de banda larga. A partir de julho, os novos planos móveis estarão disponíveis nas 300 cidades onde a Vero já possui operação móvel, criando uma nova avenida de crescimento baseada em maior geração de valor, fidelização e qualificação da base. A estratégia prevê uma expansão gradual para os demais estados onde a empresa já atua e, posteriormente, para todo o país.\nO movimento é acompanhado pela reformulação do portfólio B2C e B2B, que incorpora novas ofertas de entretenimento, inteligência artificial, telemedicina, além de cloud, segurança digital e serviços corporativos voltados à digitalização de pequenas e médias empresas.\n\"Desde o início da nossa trajetória, a Vero sempre buscou se antecipar aos movimentos do setor e construir sua estratégia a partir de uma leitura cuidadosa do mercado. A expansão do serviço móvel representa uma evolução natural do nosso negócio, porque amplia nosso mercado endereçável, fortalece a convergência e cria novas possibilidades de relacionamento com os clientes. Estamos fazendo esse movimento de forma disciplinada, com foco em rentabilidade e retorno sobre os ativos já construídos. A lógica da expansão não será volume a qualquer custo, vamos calibrar o crescimento pela resposta do mercado, aderência regional e retorno esperado\", afirma Fabiano Ferreira, CEO da Vero.\nNo segmento residencial, a companhia reformulou a lógica dos planos para ampliar a personalização da experiência do cliente, que passa a ter maior flexibilidade para construção de uma oferta mais aderente ao seu perfil. Nesse sentido, a Vero passa a comercializar os chamados superbundles, Vero Pro e Vero Pro Max, que combinam ultravelocidade, equipamentos de última geração, serviço móvel, streaming e outros benefícios em um único plano, simplificando a experiência por meio de uma relação centralizada e uma única cobrança.\nA frente de entretenimento também foi fortalecida. Além do Vero Vídeo, plataforma de TV ao vivo, a companhia passa a reunir a maior oferta de OTTs entre os ISPs do país, com a chegada de Prime Video e Appl...","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-03"},{"title":"O que acontece quando agentes de IA passam a participar das decisões de produto","title_pt":"O que acontece quando agentes de IA passam a participar das decisões de produto","url":"https://tiinside.com.br/03/06/2026/o-que-acontece-quando-agentes-de-ia-passam-a-participar-das-decisoes-de-produto/","summary":"A inteligência artificial deixou de ser apenas uma ferramenta de produtividade para se tornar parte integrante da estratégia de negócios do iFood. A empresa, que hoje processa entre 130 milhões e 160 milhões de pedidos por mês, vem ampliando o uso da tecnologia em praticamente todas as etapas de sua operação – da logística e atendimento ao cliente à personalização da experiência e ao desenvolvi...","summary_pt":"A inteligência artificial deixou de ser apenas uma ferramenta de produtividade para se tornar parte integrante da estratégia de negócios do iFood. A empresa, que hoje processa entre 130 milhões e 160 milhões de pedidos por mês, vem ampliando o uso da tecnologia em praticamente todas as etapas de sua operação – da logística e atendimento ao cliente à personalização da experiência e ao desenvolvimento de produtos.\nDurante participação na Semana de Produtos Itaú 2026, Pablo Silva, sócio e head de Produto do iFood, detalhou como a companhia vem construindo uma cultura orientada por IA e por que a empresa evita adotar a tecnologia apenas pelo apelo da novidade.\n\"A gente primeiro pergunta qual é o problema. Depois decide qual ferramenta usar. Não usamos IA por usar IA\", afirmou.\nSegundo o executivo, embora o iFood seja frequentemente reconhecido como uma empresa AI First, a relação da companhia com inteligência artificial começou muito antes da explosão recente da IA generativa. Desde seus primeiros anos, a plataforma utiliza algoritmos para otimizar rotas de entrega, prever demandas e automatizar processos operacionais em larga escala.\n\"Antes da pandemia, o iFood fazia cerca de 12 milhões de pedidos por mês. Hoje estamos entre 130 e 160 milhões. Em escala, você precisa de soluções automatizadas para operar\", explicou.\n**IA como ferramenta de negócio, não de experimentação**\nA adoção da IA dentro do iFood segue princípios já consolidados na cultura de produto da empresa. Internamente, as equipes trabalham com o chamado JIP (Jeito iFood de Fazer Produto), conjunto de diretrizes que inclui decisões orientadas por dados, foco em resultado de negócio, proximidade com o usuário e desenvolvimento incremental.\nSegundo Silva, esses princípios também orientam as iniciativas envolvendo inteligência artificial. \"Não adianta ter acesso ao melhor modelo disponível se aquilo não resolve um problema real ou não gera impacto para o negócio.\"\nEssa abordagem tem levado a empresa a separar claramente iniciativas voltadas para eficiência operacional de projetos que criam novas fontes de valor para clientes e parceiros.\n**Atendimento automatizado já supera milhões de interações**\nUm dos exemplos mais maduros dessa estratégia está no atendimento ao cliente.\nHá alguns anos, o iFood precisava lidar com volumes que chegavam a milhões de tickets mensais relacionados a problemas de pedidos, atrasos, itens faltantes ou divergências na entrega.\nPara enfrentar esse desafio, a empresa desenvolveu a ROSE, assistente virtual baseada em modelos de linguagem que hoje responde à maior parte dos atendimentos realizados na plataforma.\n\"O usuário muitas vezes prefere falar com a ROSE do que com um humano\", revelou Silva.\nSegundo ele, a empresa monitora continuamente indicadores de satisfação e qualidade das conversas para garantir que a automação não prejudique a experiência dos consumidores. Quando a IA não consegue resolver um problema, o atendimento é automaticamente transferido para ...","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-03"},{"title":"Intel reage à ofensiva da NVIDIA e reforça papel das CPUs na era da IA agêntica","title_pt":"Intel reage à ofensiva da NVIDIA e reforça papel das CPUs na era da IA agêntica","url":"https://tiinside.com.br/03/06/2026/intel-reage-a-ofensiva-da-nvidia-e-reforca-papel-das-cpus-na-era-da-ia-agentica/","summary":"Poucos dias após a NVIDIA anunciar a CPU Vera, projetada especificamente para aplicações de inteligência artificial agêntica, a Intel apresentou uma ampla atualização de seu portfólio para data centers, redes e infraestrutura de IA, reforçando uma mensagem clara ao mercado: a CPU continua sendo o elemento central para orquestração, movimentação de dados e escalabilidade dos novos ambientes de IA.","summary_pt":"Poucos dias após a NVIDIA anunciar a CPU Vera, projetada especificamente para aplicações de inteligência artificial agêntica, a Intel apresentou uma ampla atualização de seu portfólio para data centers, redes e infraestrutura de IA, reforçando uma mensagem clara ao mercado: a CPU continua sendo o elemento central para orquestração, movimentação de dados e escalabilidade dos novos ambientes de IA.\nO movimento evidencia uma disputa crescente pelo controle da arquitetura das futuras fábricas de IA. Enquanto a NVIDIA aposta em uma nova geração de processadores próprios para reduzir a dependência da arquitetura x86, a Intel responde ampliando sua família Xeon 6+, lançando novas soluções de conectividade Ethernet de até 200 GbE e revelando avanços em sua próxima geração de GPUs para inferência de inteligência artificial.\nA estratégia da fabricante norte-americana busca reafirmar a relevância das CPUs em um momento em que o mercado passa a discutir qual será o papel desses processadores em ambientes dominados por agentes de IA, modelos de raciocínio e sistemas autônomos capazes de executar tarefas complexas.\nA discussão ganhou força após a NVIDIA apresentar a CPU Vera, equipada com 88 núcleos Olympus desenvolvidos pela própria companhia e projetados para acelerar cargas de trabalho ligadas à execução de agentes, processamento de dados, compilação de código e orquestração de aplicações de IA. Segundo a fabricante, o processador entrega desempenho até 1,8 vez superior ao de CPUs x86 em determinadas aplicações e já está sendo avaliado por empresas como Anthropic, Oracle Cloud Infrastructure, NYSE e diversos provedores globais de infraestrutura de IA.\nA Intel, por sua vez, adota uma narrativa diferente. Para a companhia, a evolução da inteligência artificial não reduz a importância das CPUs, mas amplia sua relevância como plano de controle de toda a infraestrutura computacional.\n\"A IA não escala como um conjunto isolado de componentes; ela escala como um sistema coordenado\", afirmou Kevork Kechichan, vice-presidente executivo e gerente-geral do Grupo de Data Center da Intel. Segundo o executivo, os desafios atuais da IA envolvem cada vez mais concorrência entre aplicações, gerenciamento de recursos, movimentação de dados e orquestração, funções que continuam dependendo fortemente das CPUs.\n**Xeon 6+ aposta em densidade computacional e eficiência**\nO principal anúncio da Intel foi a chegada dos novos processadores Xeon 6+ com Efficient-cores (E-cores), produzidos com a tecnologia Intel 18A, utilizada pela primeira vez em um processador para data center da empresa.\nOs chips chegam ao mercado com até 288 núcleos, oferecendo, segundo a fabricante, até 2,5 vezes mais desempenho em comparação com a geração anterior. A arquitetura foi projetada para ambientes de nuvem, telecomunicações e aplicações de IA agêntica que exigem grande paralelismo, baixa latência e alta eficiência energética.\nOs processadores também incorporam memória DDR5 de 12 canais, 96 pistas PC...","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-03"},{"title":"When warranty costs rival R&D spend: Remaking vehicle quality with AI","title_pt":null,"url":"https://www.mckinsey.com/industries/automotive-and-assembly/our-insights/when-warranty-costs-rival-r-and-d-spend-remaking-vehicle-quality-with-ai","summary":"As warranty costs surge, automakers are turning to AI-enabled quality systems to detect risks earlier and reduce financial exposure.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-03","pub_date":"2026-06-03"},{"title":"Bancos avançam da experimentação de IA aplicada a operações críticas","title_pt":"Bancos avançam da experimentação de IA aplicada a operações críticas","url":"https://tiinside.com.br/03/06/2026/bancos-avancam-da-experimentacao-de-ia-aplicada-a-operacoes-criticas/","summary":"O mercado financeiro está entre os setores que mais avançam no uso de inteligência artificial, mas ainda enfrenta um desafio comum às grandes organizações: transformar pilotos e casos isolados em soluções integradas aos fluxos críticos do negócio.","summary_pt":"O mercado financeiro está entre os setores que mais avançam no uso de inteligência artificial, mas ainda enfrenta um desafio comum às grandes organizações: transformar pilotos e casos isolados em soluções integradas aos fluxos críticos do negócio.\nSegundo o relatório \"State of AI in Business 2025\", do MIT NANDA, mais de 80% das empresas já testaram ou pilotaram soluções de IA generativa, mas apenas 5% conseguiram implementar essas iniciativas em escala nos fluxos críticos de negócio. O estudo também aponta que serviços financeiros seguem entre os segmentos com alta atividade de pilotos, mas ainda com baixa transformação estrutural efetiva.\nNesse cenário, bancos e seguradoras têm ampliado os investimentos em modernização tecnológica, integração de dados e automação inteligente para acelerar ganhos de eficiência operacional e melhorar a experiência do cliente. Para a Act Digital, multinacional de tecnologia AI-first com atuação em 12 países, o setor entrou em uma nova etapa: a da IA operacional, em que o foco deixa de ser apenas a experimentação e passa a ser a geração de resultados concretos, com escala, governança e integração aos sistemas existentes.\nCom presença significativa no setor de serviços financeiros, a companhia tem acompanhado de perto o movimento das instituições em direção à hiperpersonalização, evolução de modelos de crédito, integração omnichannel e automação de processos críticos.\n\"A discussão deixou de ser apenas experimentar inteligência artificial. O mercado agora busca como escalar essas iniciativas com governança, segurança, qualidade de dados e impacto real nas áreas de negócio\", afirma Frederic Martineau, sócio e CTO da Act Digital.\nSegundo o executivo, embora a IA generativa tenha acelerado o interesse das empresas nos últimos anos, muitas organizações ainda enfrentam desafios estruturais para transformar pilotos em soluções escaláveis.\nEntre os principais gargalos estão sistemas legados, dados fragmentados, baixa integração entre plataformas, dificuldade de medir retorno e adaptação das equipes a novos modelos de trabalho com IA.\nA Act Digital atua em projetos voltados à modernização de arquitetura tecnológica, cloud, engenharia de dados, desenvolvimento de software e implementação de soluções de IA aplicadas a operações críticas do setor financeiro. A empresa trabalha com bancos, seguradoras e grandes instituições financeiras em modelos que vão desde squads especializadas até operações gerenciadas de longo prazo.\n\"O setor financeiro brasileiro possui um dos ambientes mais avançados do mundo em digitalização, Open Finance e canais conversacionais. Ao mesmo tempo, é um mercado extremamente pressionado por eficiência, experiência do cliente, segurança e velocidade de adaptação\", afirma Martineau.\nEntre as principais demandas observadas pela empresa estão projetos relacionados à automação de backoffice, prevenção a fraudes, integração de canais, personalização da jornada do cliente, modernização de plataformas e uso de a...","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-03"},{"title":"Como a Globo transformou operações de publicidade com IA e já acumula mais de 700 soluções em produção","title_pt":"Como a Globo transformou operações de publicidade com IA e já acumula mais de 700 soluções em produção","url":"https://tiinside.com.br/03/06/2026/como-a-globo-transformou-operacoes-de-publicidade-com-ia-e-ja-acumula-mais-de-700-solucoes-em-producao/","summary":"A inteligência artificial vem redefinindo a forma como empresas tradicionais conduzem seus processos, desenvolvem produtos e geram novos negócios. Durante a Semana de Produtos 2026 do Itaú, Gabriel Feitosa, PO de Produtos de Dados e IA; Ligia Costa, PO de Produtos de Dados e IA; e Miguel Jr., gerente sênior de Negócios da Globo, mostraram como a companhia vem escalando o uso de IA para simplifi...","summary_pt":"A inteligência artificial vem redefinindo a forma como empresas tradicionais conduzem seus processos, desenvolvem produtos e geram novos negócios. Durante a Semana de Produtos 2026 do Itaú, Gabriel Feitosa, PO de Produtos de Dados e IA; Ligia Costa, PO de Produtos de Dados e IA; e Miguel Jr., gerente sênior de Negócios da Globo, mostraram como a companhia vem escalando o uso de IA para simplificar operações, acelerar entregas e impulsionar a transformação digital, compartilhando desafios, aprendizados e resultados obtidos em diferentes áreas da organização.\nNo início da apresentação, Gabriel Feitosa destacou que compreender a transformação digital exige, antes de tudo, entender o contexto organizacional em que ela acontece.\nSegundo ele, empresas que nasceram digitais possuem uma vantagem natural na adoção de novas tecnologias, uma vez que seus produtos já foram concebidos em um ambiente tecnológico. Organizações tradicionais, por outro lado, precisam enfrentar desafios adicionais relacionados a processos, cultura e infraestrutura.\n\"A Globo existia antes da internet. Nosso produto principal sempre foi o conteúdo. A tecnologia não era o produto em si, mas passou a ser um elemento fundamental para potencializar sua entrega\", explicou.\nEssa diferença de origem faz com que a jornada de transformação digital em empresas tradicionais seja mais complexa. Enquanto organizações nativas digitais conseguem evoluir de forma mais ágil, empresas consolidadas precisam superar barreiras acumuladas ao longo de décadas de operação.\n**O peso da cultura na transformação digital**\nPara os executivos, embora os desafios tecnológicos sejam relevantes, a principal barreira para a transformação não está nos sistemas ou nas ferramentas.\nGabriel argumentou que questões tecnológicas tendem a ser solucionadas ao longo do tempo, seja por meio de desenvolvimento interno, aquisição de soluções ou modernização da infraestrutura. Já a mudança cultural exige um esforço contínuo de adaptação e aprendizado.\n\"O maior desafio aqui é a barreira cultural. Não só a aceitação da tecnologia, mas a capacidade de adaptação das pessoas, dos gestores e da organização como um todo.\"\nO executivo relembrou que, historicamente, empresas tradicionais costumavam ser mais avessas ao erro. No entanto, a evolução da cultura organizacional tem permitido que a Globo avance para um modelo mais experimental, no qual testar, aprender e corrigir rapidamente passou a ser parte do processo.\n\"Não existe busca pela perfeição sem erro. A gente vai fazer, errar, testar, refazer, até chegar ao resultado que deseja.\"\nSegundo Miguel Júnior, esse movimento tem sido essencial para permitir que a companhia acompanhe as transformações aceleradas do mercado de mídia, um dos segmentos mais impactados pela digitalização.\n**Dados de qualidade como pré-requisito para IA**\nOutro ponto destacado pelos palestrantes foi a importância da estruturação dos dados como etapa fundamental para qualquer iniciativa de inteligência artif...","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-03"},{"title":"Especialistas alertam para riscos de segurança e necessidade de regulação para o futuro da IA","title_pt":"Especialistas alertam para riscos de segurança e necessidade de regulação para o futuro da IA","url":"https://tiinside.com.br/03/06/2026/especialistas-alertam-para-riscos-de-seguranca-e-necessidade-de-regulacao-para-o-futuro-da-ia/","summary":"Durante o ConectaTMC, Fábio Coelho, presidente do Google Brasil, Rodrigo Lima, diretor-geral da Motorola Brasil; Frederico Succi, vice-presidente de produtos e inovação da Visa Brasil e Carlos Neto, CEO da Matera, discutiram a rápida evolução e o futuro da IA no Brasil, em seus respectivos setores, desde os desafios de segurança cibernética, até a necessidade de regulação e educação do usuário....","summary_pt":"Durante o ConectaTMC, Fábio Coelho, presidente do Google Brasil, Rodrigo Lima, diretor-geral da Motorola Brasil; Frederico Succi, vice-presidente de produtos e inovação da Visa Brasil e Carlos Neto, CEO da Matera, discutiram a rápida evolução e o futuro da IA no Brasil, em seus respectivos setores, desde os desafios de segurança cibernética, até a necessidade de regulação e educação do usuário. O bate-papo foi mediado por Felipe Bueno, apresentador da TMC.\nCoelho traz que, a partir do momento em que a IA deixou de ser restrita às empresas e ficou disponível ao público, a tecnologia tornou necessário o desenvolvimento de novos guardrails e adaptação humana. \"A IA saiu da mão das empresas para ir às pessoas e, aqui no Brasil, com um nível de adoção altíssima, temos que ter um processo de segurança ainda maior. As empresas têm que se habilitar a desenvolver soluções locais, precisamos que as pessoas se capacitem a lutar contra as ameaças e termos um regulamento que proteja, mas não limite a inovação\", explica.\nSucci acrescenta que a confiança é a base da tecnologia e que o Brasil é um \"excelente laboratório\" para testar soluções globais. \" Está muito claro que a segurança é um dos setores onde o Brasil realmente pode dar uma contribuição enorme e, não tenha dúvida, se determinada solução funciona no Brasil, ela está testada para funcionar em qualquer lugar do mundo. O nome do jogo sempre foi e vai continuar sendo confiança. A gente tem que seguir curioso, inovar e acreditar que é possível fazer um uso bastante positivo da IA com segurança\", afirma.\nJá Neto apresenta uma visão mais cautelosa e cética sobre a tecnologia. O executivo aponta para riscos no que tange à computação quântica e defende sistemas de segurança mais simples e menos dependentes de privilégios humanos. \"As pessoas fazem softwares muito complexos e colocam mil portas de segurança para garantir a segurança daquilo que não existe. Quanto mais portas fechadas, pior. O ideal é não ter porta. Então, a segurança, quanto mais simples, melhor. Eu não posso ter um sistema que não tenha ransomware, tenho que ter um sistema que tenha toda a semana, mas que não cause problema. Também, não tenho que ter privilégios. Ter privilégios é um perigo. Um funcionário com privilégios pode ter acessos a muitas informações que, talvez, ele não devesse ter\", destaca.\nPor fim, Vidigal aponta que, por mais que o brasileiro seja um \"early adopter\",  ainda há uma baixa cultura de segurança. O diretor-geral da Motorola Brasil apoia que as empresas ofereçam soluções de segurança robustas e intuitivas para os seus clientes. \"O brasileiro tem uma velocidade de adoção muito grande, mas não tem essa preocupação com a segurança, não tem um conhecimento de como utilizar os seus dados. A gente tem que trabalhar muito para que haja uma evolução nesse sentido e empregar oferecerem soluções mais robustas e completas vão permitir um uso mais seguro das tecnologias\", conclui.","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-03"},{"title":"IA deixa de ser assistente e passa a atuar como parceira estratégica na produtização do Itaú","title_pt":"IA deixa de ser assistente e passa a atuar como parceira estratégica na produtização do Itaú","url":"https://tiinside.com.br/03/06/2026/ia-deixa-de-ser-assistente-e-passa-a-atuar-como-parceira-estrategica-na-produtizacao-do-itau/","summary":"Durante a Semana de Produtos 2026, evento interno do Itaú dedicado à evolução das práticas de gestão e desenvolvimento de produtos, Diogo Boechat e Ana Paula Genari, gerentes de Plataforma de Produtos do banco, apresentaram como a inteligência artificial está transformando a forma como os times de produto trabalham, tomam decisões e desenvolvem novas soluções.","summary_pt":"Durante a Semana de Produtos 2026, evento interno do Itaú dedicado à evolução das práticas de gestão e desenvolvimento de produtos, Diogo Boechat e Ana Paula Genari, gerentes de Plataforma de Produtos do banco, apresentaram como a inteligência artificial está transformando a forma como os times de produto trabalham, tomam decisões e desenvolvem novas soluções.\nDurante apresentação sobre a evolução da estratégia de IA aplicada à produtização, os executivos mostraram como o banco está utilizando inteligência artificial para simplificar processos, reduzir a complexidade operacional e ampliar a capacidade analítica das equipes. No centro dessa transformação está a UPOPS, plataforma desenvolvida para reunir dados, contexto e inteligência em um único ambiente de trabalho.\nSegundo eles, a iniciativa representa mais uma etapa na jornada de transformação da organização.\n\"Passamos por uma transformação digital, passamos por uma transformação de produtação e agora estamos vivendo uma transformação de inteligência artificial\", destacou Boechat.\nHoje, o Itaú já contabiliza mais de 760 casos de uso de IA, sendo mais de 150 em produção. Os números, segundo o executivo, crescem rapidamente e já se aproximam da marca de mil iniciativas.\nAs aplicações vão desde modernização tecnológica até agentes inteligentes capazes de identificar oportunidades de eficiência, reduzir custos operacionais em até 72% e antecipar incidentes antes que eles afetem operações críticas.\nMas o foco da apresentação foi outro: mostrar como a inteligência artificial está sendo incorporada ao próprio processo de desenvolvimento de produtos.\n**Da teoria à prática: o desafio de operacionalizar a excelência**\nA origem da UPOPS está diretamente ligada à evolução do Jeito Itaú de Produtar (JIP), iniciativa criada para consolidar práticas, métodos e referências para os profissionais de produto da instituição.\nEm um primeiro momento, a equipe estruturou um arcabouço metodológico e o colocou à prova com cerca de 50 squads. Embora o conteúdo tenha sido bem recebido, os feedbacks apontaram um desafio importante.\nOs profissionais enxergavam valor no método, mas encontravam dificuldades para incorporá-lo à rotina.\n\"É super legal, isso aqui me ajuda a produtar no dia a dia, mas é muito difícil operacionalizar\", relembrou Boechat ao citar as percepções coletadas junto às equipes.\nO diagnóstico revelou uma realidade comum entre os gestores de produto. Muitos utilizavam dezenas de ferramentas simultaneamente, navegando constantemente entre dashboards, sistemas de backlog, plataformas de monitoramento, indicadores de experiência e bases de conhecimento.\nEm vez de criar mais um framework, a equipe decidiu atacar o problema pela raiz: simplificar o acesso à informação. A pergunta passou a ser simples. E se todas essas fontes estivessem reunidas em um único ambiente?\nFoi dessa reflexão que nasceu a UPOPS.\n**Uma plataforma construída para reduzir a complexidade**\nA UPOPS foi concebida como uma camada única de ...","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-03"},{"title":"Assistente virtual da VR usa IA para resolver até 98% das dúvidas  sem atendimento humano","title_pt":"Assistente virtual da VR usa IA para resolver até 98% das dúvidas  sem atendimento humano","url":"https://tiinside.com.br/02/06/2026/assistente-virtual-da-vr-usa-ia-para-resolver-ate-98-das-duvidas-sem-atendimento-humano/","summary":"Bem-vindo! Entre na sua conta","summary_pt":"Bem-vindo! Entre na sua conta\nUma senha será enviada por e-mail para você.\n### [Relatório do Impacto dos Dados e da IA: Mergulhe na pesquisa](https://www.sas.com/pt_br/gc/data-and-ai-impact-report.html\\#download\\#new_tab \"Relatório do Impacto dos Dados e da IA: Mergulhe na pesquisa\")","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-02"},{"title":"The Download: AI can run your admin department now","title_pt":null,"url":"https://www.technologyreview.com/2026/06/02/1138277/the-download-ai-tips-small-businesses-admin/","summary":"This is today&#8217;s edition of The Download, our weekday newsletter that provides a daily dose of what&#8217;s going on in the world of technology. How small businesses can leverage AI From accounting to design to market research and product development, there’s a staggering breadth of skills needed to run a business. Large companies can hire&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-02","pub_date":"2026-06-02"},{"title":"Rehumanizing global health care with agentic AI","title_pt":null,"url":"https://www.technologyreview.com/2026/06/02/1137827/rehumanizing-global-health-care-with-agentic-ai/","summary":"The global health care sector is under increasing strain.&#160; Decades of chronic underinvestment and constraints in recruitment have coincided with a surge in demand for services for aging populations. Gaps in provision are already taking a toll, with fragmented access to care and high rates of stress and burnout among staff. And it’s getting worse.&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-02","pub_date":"2026-06-02"},{"title":"The next gold rush: How the Bay Area can keep its edge in the AI era","title_pt":null,"url":"https://www.mckinsey.com/industries/social-sector/our-insights/the-next-gold-rush-how-the-bay-area-can-keep-its-edge-in-the-ai-era","summary":"San Francisco is driving the AI revolution. How can the Bay Area sustain and expand this innovation ecosystem in the years to come?","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-03","pub_date":"2026-06-02"},{"title":"Oracle investe em agentes de IA e amplia ecossistema para próxima geração da inteligência artificial","title_pt":"Oracle investe em agentes de IA e amplia ecossistema para próxima geração da inteligência artificial","url":"https://tiinside.com.br/02/06/2026/oracle-investe-em-agentes-de-ia-e-amplia-ecossistema-para-proxima-geracao-da-inteligencia-artificial/","summary":"Durante o Oracle Data Deep Dive, realizado em 21 de maio, em São Paulo, a companhia deixou claro que sua estratégia para inteligência artificial vai muito além da corrida por modelos generativos.","summary_pt":"Durante o Oracle Data Deep Dive, realizado em 21 de maio, em São Paulo, a companhia deixou claro que sua estratégia para inteligência artificial vai muito além da corrida por modelos generativos.\nEm uma apresentação conduzida por Leandro Vieira, vice-presidente de IA e Tech Cloud para a América Latina, e Marcelo Christianini, vice-presidente de IA e Cloud Engineering da companhia na região, a empresa apresentou sua visão para a próxima fase da IA corporativa: um cenário baseado em agentes inteligentes, integração entre aplicações e dados, arquiteturas escaláveis e forte governança.\nMais do que anunciar novas funcionalidades, a Oracle aproveitou o evento para reforçar um posicionamento estratégico que vem se consolidando dentro da companhia: o de atuar como a camada estrutural da IA corporativa. Na visão dos executivos, o diferencial competitivo das empresas nos próximos anos não estará apenas no acesso aos modelos de IA, mas na capacidade de conectar agentes, infraestrutura, segurança e dados de forma consistente.\n\"A interação homem-sistema vai mudar muito nos próximos anos\", afirmou Leandro Vieira. \"Durante muito tempo operamos sistemas por meio do computador ou do celular. Agora começamos a entrar em uma fase em que os agentes executam automaticamente aquilo que precisa ser feito.\"\n**A aposta da Oracle na IA agentic**\nA Oracle apresentou durante o evento uma série de iniciativas voltadas à chamada IA agentic, conceito baseado em agentes autônomos capazes de executar tarefas, tomar decisões contextuais e interagir com diferentes sistemas corporativos.\nEntre as novidades destacadas estão recursos como MCP Server e Agent Factory, plataforma que permite executar agentes diretamente dentro do banco de dados. Segundo Marcelo Christianini, a integração entre IA, infraestrutura e dados será um dos pilares centrais da próxima geração de aplicações empresariais.\n\"A parte do MCP Server é muito importante para conectar os agentes diretamente. E o Agent Factory permite rodar agentes dentro do próprio banco de dados\", explicou.\nNa prática, a visão da Oracle é transformar aplicações corporativas em ambientes capazes de operar com agentes inteligentes executando tarefas de maneira autônoma, reduzindo a dependência de interfaces tradicionais e automatizando fluxos inteiros de trabalho.\nPara a companhia, essa transformação será comparável ao impacto provocado anteriormente pela chegada da internet, da computação em nuvem e da mobilidade.\n**Governança e arquitetura ganham protagonismo**\nAo longo da apresentação, os executivos reforçaram diversas vezes que a adoção de IA corporativa não pode ser baseada apenas em velocidade ou experimentação rápida.\nA Oracle defendeu que empresas precisarão construir fundações sólidas envolvendo arquitetura, governança, segurança e gestão de dados para conseguir escalar projetos de inteligência artificial de forma sustentável.\n\"O mundo está mudando rápido demais para criar novos legados tecnológicos\", afirmou Leandro Vieira.\nA ...","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-02"},{"title":"How small businesses can leverage AI","title_pt":null,"url":"https://www.technologyreview.com/2026/06/02/1138227/how-small-businesses-can-leverage-ai/","summary":"This article is from Making AI Work, MIT Technology Review’s limited-run newsletter examining how to apply LLMs across industries. To receive it in your inbox,sign up here. From accounting to design to market research and product development, there’s a staggering breadth of skills needed to run a business. A large company can hire experts to&#8230;","summary_pt":null,"source_id":"mit","first_seen":"2026-06-02","pub_date":"2026-06-02"},{"title":"When AI becomes part of the workflow: Redesigning how software gets built","title_pt":null,"url":"https://www.mckinsey.com/capabilities/mckinsey-technology/overview/when-ai-becomes-part-of-the-workflow-redesigning-how-software-gets-built","summary":"AI is already transforming how software is built—but most organizations are capturing only a fraction of its value. At Sonar, teams redesigned the product development life cycle and showed AI can unlock step-change gains in speed, quality, and scalability.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-03","pub_date":"2026-06-01"},{"title":"IA deixa de ser promessa e se torna fator decisivo para o futuro dos bancos","title_pt":"IA deixa de ser promessa e se torna fator decisivo para o futuro dos bancos","url":"https://tiinside.com.br/01/06/2026/ia-deixa-de-ser-promessa-e-se-torna-fator-decisivo-para-o-futuro-dos-bancos/","summary":"A transformação digital dos bancos entrou em uma nova fase. Depois de anos investindo em canais digitais, aplicativos e automação, as instituições financeiras agora enfrentam um desafio mais complexo: transformar inteligência artificial, dados e personalização em vantagem competitiva real.","summary_pt":"A transformação digital dos bancos entrou em uma nova fase. Depois de anos investindo em canais digitais, aplicativos e automação, as instituições financeiras agora enfrentam um desafio mais complexo: transformar inteligência artificial, dados e personalização em vantagem competitiva real.\nEssa é uma das principais conclusões do FinFacts 2026, estudo do Google Cloud que chega à sua quinta edição analisando a maturidade digital das instituições financeiras brasileiras. Apresentado por Rafael d'Ávila, Líder de Serviços Financeiros do Google Cloud Brasil, o levantamento mostra um setor que avança rapidamente na adoção de novas tecnologias, mas que ainda precisa superar barreiras estruturais para capturar todo o potencial da inteligência artificial.\nMais do que uma avaliação de funcionalidades digitais, o estudo retrata um mercado pressionado por consumidores cada vez mais exigentes, pela evolução regulatória e pela necessidade de equilibrar eficiência operacional, personalização e segurança.\n\"O que deixou de ser o futuro passou a ser o presente do setor financeiro\", resumiu Rafael durante a apresentação.\n**O peso dos sistemas legados sobre a eficiência bancária**\nO ponto de partida do estudo é um paradoxo que vem preocupando o setor financeiro global.\nEmbora os bancos invistam cerca de US$650 bilhões por ano em tecnologia, a produtividade da indústria apresentou queda ao longo da última década. Segundo Rafael, o fenômeno está diretamente relacionado à complexidade operacional acumulada pelas instituições ao longo dos anos.\nBoa parte dos bancos tradicionais ainda opera sobre estruturas tecnológicas construídas em momentos diferentes, utilizando sistemas que nem sempre compartilham informações entre si. São plataformas responsáveis por sustentar operações críticas (como contas correntes, crédito, investimentos e segurança), mas que frequentemente funcionam de forma isolada.\nNa prática, isso gera experiências fragmentadas para os clientes e limita a capacidade das instituições de oferecer serviços realmente personalizados.\n\"Quando um banco pede novamente uma informação que já possui, isso é um sinal claro de ineficiência\", afirmou. Segundo o executivo, a existência de silos de dados deixou de ser apenas um problema tecnológico e passou a representar uma limitação estratégica para os negócios.\n**A experiência se tornou o principal diferencial competitivo**\nA necessidade de modernização se torna ainda mais urgente em um cenário de concorrência sem precedentes. O estudo destaca que existem mais de 31 mil fintechs em operação no mundo, além do avanço de big techs, marketplaces e plataformas digitais que disputam a atenção dos consumidores.\nAo mesmo tempo, 60% dos clientes já preferem contratar produtos financeiros de forma totalmente digital. Nesse contexto, a experiência do usuário passa a ser o principal fator de diferenciação.\n\"A lealdade deixou de estar associada ao tempo de relacionamento. Hoje ela depende da qualidade da experiência entregue\", des...","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-01"},{"title":"84% das empresas de tecnologia incentivam o uso de IA, aponta estudo","title_pt":"84% das empresas de tecnologia incentivam o uso de IA, aponta estudo","url":"https://tiinside.com.br/01/06/2026/84-das-empresas-de-tecnologia-incentivam-o-uso-de-ia-aponta-estudo/","summary":"Bem-vindo! Entre na sua conta","summary_pt":"Bem-vindo! Entre na sua conta\nUma senha será enviada por e-mail para você.\n### [Relatório do Impacto dos Dados e da IA: Mergulhe na pesquisa](https://www.sas.com/pt_br/gc/data-and-ai-impact-report.html\\#download\\#new_tab \"Relatório do Impacto dos Dados e da IA: Mergulhe na pesquisa\")","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-01"},{"title":"Governança inadequada pode levar empresas a desativar agentes autônomos de IA, alerta Gartner","title_pt":"Governança inadequada pode levar empresas a desativar agentes autônomos de IA, alerta Gartner","url":"https://tiinside.com.br/01/06/2026/governanca-inadequada-pode-levar-empresas-a-desativar-agentes-autonomos-de-ia-alerta-gartner/","summary":"Bem-vindo! Entre na sua conta","summary_pt":"Bem-vindo! Entre na sua conta\nUma senha será enviada por e-mail para você.\n### [Relatório do Impacto dos Dados e da IA: Mergulhe na pesquisa](https://www.sas.com/pt_br/gc/data-and-ai-impact-report.html\\#download\\#new_tab \"Relatório do Impacto dos Dados e da IA: Mergulhe na pesquisa\")","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-01"},{"title":"Inter vê impulso em retenção de clientes e transações após integrar Open Finance e IA","title_pt":"Inter vê impulso em retenção de clientes e transações após integrar Open Finance e IA","url":"https://tiinside.com.br/01/06/2026/inter-ve-impulso-em-retencao-de-clientes-e-transacoes-apos-integrar-open-finance-e-ia/","summary":"Durante o APIX 2026, Gustavo Borges, Superintendente do Inter, detalhou os aprendizados práticos, a evolução do ecossistema financeiro e a trajetória do Open Finance no Brasil. O executivo destaca o desenvolvimento de um \"super app\" financeiro global\", marcado por \"inovação e visão de futuro\".","summary_pt":"Durante o APIX 2026, Gustavo Borges, Superintendente do Inter, detalhou os aprendizados práticos, a evolução do ecossistema financeiro e a trajetória do Open Finance no Brasil. O executivo destaca o desenvolvimento de um \"super app\" financeiro global\", marcado por \"inovação e visão de futuro\".\nBorges aponta que, apesar de visto inicialmente como obrigação regulatória, o Open Finance passou a ser encarado pelo Inter como uma oportunidade de gerar valor. \"Ele é um aliado, na verdade. A grande vantagem que a gente vê é a centralização de dados. Foi-se a época que tinha-se um banco só, que normalmente era aquele banco que você recebia seu salário. Hoje, todo mundo tem dois e a coisa está democratizada. E aí as suas informações, seus investimentos, seus créditos também estão\", afirma.\nO superintendente, também, destaca resultados expressivos após \"mergulhar de vez\" no Open Finance. \"Em 2024, a gente teve 18 mil transações, muito pouco. Em 2025, a gente foi para 172 mil e, em 2026, a gente já está com mais de 1 milhão. Já estamos com 423 mil vínculos e 14 milhões de pagamentos realizados, 8 vezes o número de transações só nos 3 primeiros meses desse ano. 2 milhões de transações por mês, isso é 64 vezes o número de transações desde a entrada da jornada sem redirecionamento.\"\nO executivo traz que o Inter possui uma plataforma, denominada Motor de Qualidade de Dados (MQD), para assegurar a qualidade e extrair valor dos dados. Segundo o superintendente, o MQD permite que o banco enriqueça seus modelos de crédito com informações em tempo real de outras instituições e evite a evasão de clientes. \"A gente pode entender o que aquele outro investimento está oferecendo e entender como eu posso reter o cliente que quer ir embora. Foi quando a gente passou a usar o dado do MQD para enriquecer nossos modelos de crédito e fazer uma concessão melhor, para dar melhores códigos, para dar um valor justo, para dar uma taxa, não olhando só para aquela informação, que conseguimos manter a taxa de retenção\", explica.\nBorges, ainda, enfatiza a integração do novo agente de IA do banco, denominado \"Seven\". O objetivo é que a ferramenta, aliada ao Open Finance, permita a gestão financeira inteligente, saldos unificados e transações simplificadas por voz ou chat. \"Dentro do aplicativo do Inter hoje, a gente já tem uma IA que você consegue conversar com ela, você consegue transacionar, você consegue falar com o seu extrato, você consegue fazer um PIX, e tudo isso também para o Whatsapp. Eu posso fazer personalização, eu entendo o meu cliente.  Então, a potencialização do Open Finance com o mundo de agentes, com o IA, é gigante\", aponta.\nPor fim, Borges afirma que a Inter projeta uma \"grande virada de mercado\", com a expansão da portabilidade de crédito via Open Finance, que aumentará a competitividade e beneficiará o consumidor final, até 2028. \"Olhando para o Open Finance, olhando para o Inter, para a tecnologia, a portabilidade de crédito, como eu falei, ela se torna real. \"...","source_id":"tiinside","first_seen":"2026-06-06","pub_date":"2026-06-01"},{"title":"How the Pope’s Magnifica Humanitas offers a template for individuals to meet the AI moment","title_pt":"Como a 'Magnifica Humanitas' do Papa oferece um modelo para que indivíduos enfrentem o momento da IA","url":"https://www.technologyreview.com/2026/05/29/1138107/how-the-popes-magnifica-humanitas-offers-a-template-for-individuals-to-meet-the-ai-moment/","summary":"Pope Leo XIV’s new encyclical on artificial intelligence includes a statement that warrants serious attention from technologists and policymakers: “Technology is never neutral.” Magnifica Humanitas (“Magnificent Humanity”) is a clarion call to all people to act with courage and solidarity as we enter an age already being transformed by artificial intelligence, the greatest change in&#8230;","summary_pt":"O artigo da MIT Technology Review analisa a encíclica papal \"Magnifica Humanitas\" (Magnífica Humanidade), publicada pelo Papa Leão XIV em maio de 2026, como um chamado ético e político à ação diante do avanço da inteligência artificial. A afirmação central do documento — \"a tecnologia nunca é neutra\" — é apresentada como ponto de partida para uma reflexão sobre responsabilidade coletiva num momento em que a IA está transformando o mundo com velocidade comparável à Revolução Industrial.\r\n\r\nOs autores argumentam que, na ausência de regulação efetiva por parte de governos e organismos internacionais, investidores institucionais têm preenchido esse vácuo. Coalizões como o Interfaith Center on Corporate Responsibility, representando mais de US$ 400 bilhões em ativos, têm apresentado resoluções em assembleias de acionistas de empresas como Alphabet, Amazon, Nvidia, Meta e Microsoft, exigindo transparência e responsabilização no uso da IA.\r\n\r\nA encíclica é posicionada não como ruptura, mas como ratificação de uma agenda de governança que já está em movimento. Com OpenAI, Anthropic e xAI se preparando para abrir capital, os mesmos mecanismos de pressão acionária poderão ser aplicados a empresas que hoje são privadas e praticamente imunes a esse tipo de escrutínio.","source_id":"mit","first_seen":"2026-05-31","pub_date":"2026-05-29"},{"title":"When AI meets desire: Innovating human-centered luxury experiences in the agentic age","title_pt":"Quando a IA encontra o desejo: inovando experiências de luxo centradas no ser humano na era agêntica","url":"https://www.mckinsey.com/industries/retail/our-insights/when-ai-meets-desire-innovating-human-centered-luxury-experiences-in-the-agentic-age","summary":"With luxury consumers rapidly embracing AI, the strategic question for merchants is no longer whether agents will mediate the journey, but who controls how brands are perceived.","summary_pt":"O relatório da McKinsey analisa como o comércio agêntico — mediado por assistentes de IA como Gemini, ChatGPT e Perplexity — está transformando a jornada de compra no setor de luxo. A tese central é que a \"porta de entrada\" da experiência de luxo está migrando para upstream: antes mesmo de o cliente chegar à boutique ou ao site da marca, sua intenção de compra já está sendo interpretada e moldada por sistemas de IA de terceiros. Segundo a pesquisa, 85% dos consumidores de luxo já usam assistentes de IA multipropósito para decisões de compra.\r\n\r\nO desafio estratégico não é tecnológico, mas de autoridade interpretativa: quem define como a marca é percebida quando um agente de IA é o primeiro ponto de contato? Se uma ferramenta genérica for a primeira a interpretar o desejo de um cliente, o risco não é receber uma sugestão errada de produto, mas ter a própria identidade da marca distorcida. A McKinsey estima que agentes de IA poderão mediar entre US$ 3 trilhões e US$ 5 trilhões do comércio global de bens até 2030.\r\n\r\nO relatório propõe um modelo conceitual de quatro \"salas\": o Foyer (descoberta inicial), a Galeria (curadoria de produtos), o Salão (autorização supervisionada com humanos no centro) e o Ateliê (pós-venda e fidelização). Cada sala exige um nível diferente de delegação à IA.\r\n\r\nPara líderes do setor, as implicações são concretas: marcas de luxo precisam codificar seus códigos estéticos e de serviço em formatos legíveis por máquina, construir camadas de interpretação de marca próprias e encarar a confiança como ativo de diferenciação. Esperar para agir é, em si, uma escolha estratégica arriscada.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-29"},{"title":"The future of AI and trade","title_pt":null,"url":"https://www.mckinsey.com/mgi/media-center/the-future-of-ai-and-trade","summary":"For all the constant buzz around AI, broad-based announcements about how AI has boosted profits are noticeably missing. The reason for this loud silence: it hasn’t happened—yet, write Olivia White and Tiago Devesa.","summary_pt":null,"source_id":"mckinsey","first_seen":"2026-06-02","pub_date":"2026-05-29"},{"title":"AI is already rewiring the aftermarket and services","title_pt":"A IA já está reconfigurando o pós-venda e os serviços na indústria automotiva e de manufatura","url":"https://www.mckinsey.com/industries/automotive-and-assembly/our-insights/ai-is-already-rewiring-the-aftermarket-and-services","summary":"For industrial companies, applying AI to the aftermarket and services could provide a source for differentiation on top of cost and time savings and enhanced customer experiences.","summary_pt":"O relatório da McKinsey examina como a inteligência artificial está transformando o mercado de pós-venda e serviços nas indústrias automotiva e industrial — segmentos que historicamente respondem pela maior parte das margens das empresas do setor. Em empresas de elevadores e escadas rolantes, por exemplo, os serviços podem representar até três quartos das margens totais.\r\n\r\nO artigo detalha como a IA está remodelando cada etapa do ciclo de vida de serviços: da inovação e desenvolvimento de produtos (com gêmeos digitais que reduzem custos de P&D em até 5%) à geração de demanda (copilots de vendas que dobraram as oportunidades de novos contratos em um OEM industrial), passando pela execução de ordens de serviço (diagnóstico remoto que reduziu horas de trabalho por tarefa em 15%).\r\n\r\nApesar do potencial, a McKinsey alerta que apenas cerca de 5% do EBIT das empresas pode ser atribuído ao uso de IA generativa. Os principais obstáculos são: falta de caminho claro do piloto para a escala, gestão insuficiente de dados, baixa adoção por parte das equipes de campo e dificuldades de integração com sistemas existentes.\r\n\r\nPara líderes industriais, o roteiro prático é: identificar os dois ou três momentos da jornada de serviço que mais impactam margem e experiência do cliente, definir quais decisões a IA deve automatizar versus apoiar, e garantir ownership claro para os resultados.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-29"},{"title":"Rewiring software delivery for the agentic era","title_pt":"Reconfigurando a entrega de software para a era agêntica","url":"https://www.mckinsey.com/capabilities/mckinsey-technology/our-insights/rewiring-software-delivery-for-the-agentic-era","summary":"The way agentic AI is being used in software development is a harbinger for broader changes in the delivery model.","summary_pt":"Este artigo da McKinsey descreve como a IA agêntica está transformando radicalmente os modelos de entrega de software. O ponto de partida é um modelo de trabalho de 24 horas: durante o dia, equipes humanas revisam entregas e refinam guardrails; durante a noite, agentes de IA executam tarefas estruturadas em escala. Empresas pioneiras já relatam ganhos de três a cinco vezes na produtividade, com redução de 60% no tamanho das equipes.\r\n\r\nO artigo estrutura a transformação em quatro pilares: o sprint diário de 24 horas; a automação de handoffs entre requisitos, código e testes; a construção de uma infraestrutura de conhecimento em grafos semânticos como memória institucional; e a captura de valor por meio do redimensionamento de equipes.\r\n\r\nPara líderes de tecnologia, as implicações são profundas: as funções de engenharia migrarão de produção manual de código para supervisão, revisão arquitetural e modelagem de domínio. As organizações que começarem agora a reconstruir seu modelo operacional em torno da colaboração humano-agente redefinirão como o software cria valor.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-28"},{"title":"The Download: climate tech goes public and the AI Hype Index returns","title_pt":"O Download: empresas de tecnologia climática abrem capital e o Índice de Hype da IA retorna","url":"https://www.technologyreview.com/2026/05/28/1138085/the-download-climate-tech-ipos-ai-hype-index/","summary":"This is today&#8217;s edition of The Download, our weekday newsletter that provides a daily dose of what&#8217;s going on in the world of technology. Climate tech companies are going public. What’s next? Solar and battery company Solv Energy went public in February, hitting a $6 billion valuation. X-energy, which builds small modular nuclear reactors, followed&#8230;","summary_pt":"Esta edição do boletim diário The Download da MIT Technology Review traz dois temas centrais: a onda de IPOs de empresas de tecnologia climática e o retorno do Índice de Hype da IA. No front climático, Solv Energy, X-energy e Fervo Energy abriram capital com valuations bilionários em 2026, impulsionadas pela demanda crescente por energia limpa — em grande parte alimentada pelos data centers da era da IA.\r\n\r\nOutros destaques incluem: a ByteDance desenvolvendo CPUs customizadas diante da escassez de chips de IA; quatro gigantes da tecnologia (Amazon, Google, Meta e Microsoft) se unindo a uma iniciativa de energia limpa para data centers; e Jensen Huang, da Nvidia, ingressando no conselho da Universidade Tsinghua em Pequim. A newsletter oferece um panorama rico da interseção entre IA, energia e geopolítica.","source_id":"mit","first_seen":"2026-05-31","pub_date":"2026-05-28"},{"title":"Move first or fall behind: How AI is rewriting the rules of banking","title_pt":"Mova-se primeiro ou fique para trás: como a IA está reescrevendo as regras do setor bancário","url":"https://www.mckinsey.com/industries/financial-services/our-insights/move-first-or-fall-behind-how-ai-is-rewriting-the-rules-of-banking","summary":"AI is poised to reshape banking not just by cutting costs, but by redistributing profits, redefining customer relationships, and accelerating competition. How should banks respond?","summary_pt":"Este episódio do podcast McKinsey traz o sócio sênior Ido Segev discutindo como a IA representa uma transformação estrutural — e não apenas incremental — para o setor bancário. A questão central para os bancos não é mais se devem adotar IA, mas com que velocidade e profundidade. O maior risco é a inércia: bancos que se moverem cedo capturarão vantagens de custo e rentabilidade que os atrasados não conseguirão recuperar facilmente.\r\n\r\nOs números são expressivos: Segev estima que a adoção plena de IA agêntica pode reduzir os custos bancários em 20 a 25%, o equivalente a US$ 250 a US$ 500 milhões por cada US$ 100 bilhões em ativos. Ao mesmo tempo, a competição deve comprimir os lucros da indústria em 9 a 10% ao longo do tempo.\r\n\r\nSegev identifica os principais obstáculos para escalar IA nos bancos: falta de foco nas iniciativas, silos entre áreas de negócio e TI, necessidade de requalificação dos funcionários, e a armadilha de confundir capacidade liberada com valor gerado. Para líderes do setor financeiro, as implicações são claras: os vencedores serão os bancos que adotarem IA de forma precisa — não necessariamente os maiores, mas os mais estratégicos.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-28"},{"title":"The AI Hype Index: AI gets booed in graduation season","title_pt":"O Índice de Hype da IA: a IA recebe vaias na temporada de formatura","url":"https://www.technologyreview.com/2026/05/28/1138053/the-ai-hype-index-ai-gets-booed-in-graduation-season/","summary":"It is one thing to say AI will change the world. It is another to expect the class of 2026 to applaud it. In fact, when former Google CEO Eric Schmidt told University of Arizona graduates that their task is to help shape AI, he was met with a resounding chorus of boos. “I can&#8230;","summary_pt":"A coluna \"AI Hype Index\" da MIT Technology Review registra um momento incomum: em cerimônias de formatura em universidades americanas, discursos de executivos do setor de tecnologia sobre IA foram recebidos com vaias dos formandos. O ex-CEO do Google Eric Schmidt, ao dizer que a missão dos formandos era ajudar a moldar a IA, ouviu um coro de desaprovação — ao que reconheceu que os medos sobre desemprego e um futuro incerto são \"racionais\".\r\n\r\nO episódio captura uma tensão crescente na sociedade: ao mesmo tempo em que a IA continua avançando e atraindo investimentos recordes, a geração que está entrando no mercado de trabalho demonstra ceticismo explícito e até hostilidade em relação à tecnologia. Para líderes empresariais, isso representa um sinal de alerta importante sobre a necessidade de narrativas mais honestas e empáticas ao comunicar estratégias de adoção de IA.","source_id":"mit","first_seen":"2026-05-31","pub_date":"2026-05-28"},{"title":"The surprising economics of B2B growth: The new survival thresholdâand what it takes to thrive","title_pt":"A economia surpreendente do crescimento B2B: o novo limiar de sobrevivência e o que é preciso para prosperar","url":"https://www.mckinsey.com/capabilities/growth-marketing-and-sales/our-insights/the-surprising-economics-of-b2b-growth-the-new-survival-threshold-and-what-it-takes-to-thrive","summary":"The 2026 Global B2B Pulse Survey finds a divide between leaders and laggardsâand shows how integrating hyperpersonalization, AI, and sales accountability creates a new operating system for growth.","summary_pt":"Baseado na Pesquisa Global B2B Pulse 2026 da McKinsey com quase 4.000 tomadores de decisão em 13 países, este artigo revela uma divisão crescente entre líderes e retardatários no mercado B2B. A conclusão central é que omnichannel e e-commerce, antes diferenciais competitivos, tornaram-se o mínimo necessário para sobreviver. Setenta e um por cento das empresas B2B já oferecem e-commerce, e cerca de um terço das receitas flui por canais digitais.\r\n\r\nO estudo identifica três motores que separam os líderes dos demais: hiperpersonalização real (um para um), escalonamento de IA generativa integrada aos fluxos comerciais e governança disciplinada de marketing baseado em contas (ABM). Sessenta por cento dos líderes reportam crescimento de receita de dois dígitos, contra apenas 21% dos retardatários.\r\n\r\nAs implicações práticas para empresas B2B são significativas: não basta investir em qualquer uma dessas capacidades isoladamente. A vantagem real vem da integração — dados unificados de clientes que alimentam modelos de IA, que por sua vez habilitam personalização em escala, gerida com accountability clara de vendas.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-28"},{"title":"Building the AI advantage: How ADEO is preparing for retailâs next wave","title_pt":"Construindo a vantagem da IA: como a ADEO se prepara para a próxima onda do varejo","url":"https://www.mckinsey.com/industries/retail/our-insights/building-the-ai-advantage-how-adeo-is-preparing-for-retails-next-wave","summary":"The global home-improvement retailerâs chief digital and information officer on unlocking the potential of AIâand keeping peopleâs feet on the ground.","summary_pt":"O relatório da McKinsey examina como a ADEO, grupo francês de varejo de home improvement que controla marcas como Leroy Merlin, está se preparando estrategicamente para a transformação impulsionada pela inteligência artificial no setor varejista. A ADEO apostou em criar uma infraestrutura de dados unificada que conecta suas diversas unidades de negócio ao redor do mundo, permitindo que algoritmos de IA personalizem a experiência de compra, otimizem estoques e melhorem a cadeia de abastecimento.\r\n\r\nA empresa investe em capacitação interna para que colaboradores em toda a organização possam usar ferramentas de IA no dia a dia, disseminando a cultura de dados como diferencial competitivo. O caso da ADEO ilustra que a transformação por IA no varejo não é apenas uma questão tecnológica, mas organizacional: exige governança de dados robusta, alinhamento entre áreas de negócio e TI, e liderança disposta a tolerar experimentos e falhas rápidas.\r\n\r\nA conclusão do artigo reforça que o varejo do futuro pertence a quem conseguir transformar volume massivo de dados em decisões inteligentes em tempo real. Mesmo grupos tradicionais e multigeográficos podem liderar essa onda se investirem de forma consistente em fundações de dados e em uma cultura organizacional orientada à IA.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-28"},{"title":"The boardâs role in managing emerging AI risks","title_pt":"O papel do conselho na gestão dos riscos emergentes de IA","url":"https://www.mckinsey.com/capabilities/mckinsey-technology/overview/cybersecurity/the-boards-role-in-managing-emerging-ai-risks","summary":"Leading cybersecurity executives and board directors discuss the challenges and opportunities of AI.","summary_pt":"Este artigo da McKinsey explora como as lideranças corporativas devem repensar a governança diante da transformação acelerada pela IA. Executivos de segurança e membros de conselhos de administração identificam quatro prioridades centrais: fortalecer a governança e a accountability, equilibrar inovação com gestão de riscos, construir capacidades de gestão de risco em tempo real e melhorar a fluência em IA nos conselhos.\r\n\r\nO debate destaca que a IA representa a maior transformação da geração atual: diferente de software convencional, ela é embedded em todos os sistemas e modifica o paradigma de segurança para uma superfície de ataque multidirecional. Organizações líderes em engenharia estão avançando rapidamente porque integram segurança ao design dos sistemas desde o início.\r\n\r\nPara conselhos e líderes de tecnologia, as implicações práticas incluem: criar comitês de tecnologia dedicados com fluência em IA, estabelecer frameworks de IA responsável com revisão contínua, e aprender com os erros de outros sem esperar errar internamente. A IA está cruzando o limiar de tópico de inovação para risco corporativo central, exigindo novos modelos de reporte e accountability explícita.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-27"},{"title":"The Download: keeping up with AI, and the future of IVF","title_pt":"O Download: acompanhando a IA e o futuro da fertilização in vitro","url":"https://www.technologyreview.com/2026/05/27/1138048/the-download-ai-future-ivf-technology/","summary":"This is today&#8217;s edition of The Download, our weekday newsletter that provides a daily dose of what&#8217;s going on in the world of technology. Stay on top of what’s going on in AI this summer Here at MIT Technology Review, we understand exactly how relentless the pace of news from the world of artificial intelligence&#8230;","summary_pt":"Esta edição do The Download da MIT Technology Review aborda como acompanhar o ritmo acelerado das novidades em IA e uma reportagem aprofundada sobre como novas tecnologias estão transformando o processo de fertilização in vitro (FIV). Pesquisadores estão usando IA para identificar espermatozoides e embriões com maior potencial, desenvolvendo sistemas robóticos para automatizar partes do processo e explorando técnicas de edição genética para prevenir doenças hereditárias.\r\n\r\nOs destaques adicionais incluem: a NASA revelando planos para três missões não tripuladas à Lua em 2026; a Huawei anunciando um avanço no design de chips que a posicionaria como líder em cinco anos; e o crescimento acelerado da demanda por especialistas em cibersegurança impulsionado pelo boom da IA. Para executivos de tecnologia e líderes da área de saúde, esta edição sinaliza a convergência acelerada entre IA e biomedicina.","source_id":"mit","first_seen":"2026-05-31","pub_date":"2026-05-27"},{"title":"Rethinking organizational design in the age of agentic AI","title_pt":"Repensando o design organizacional na era da IA agêntica","url":"https://www.technologyreview.com/2026/05/26/1137584/rethinking-organizational-design-in-the-age-of-agentic-ai/","summary":"Amid rapidly growing adoption of enterprise-level AI agents, there’s a disconnect emerging between ambition and execution.&#160; Although 85% of organizations say they want to be agentic within the next three years, 76% say their current operations and infrastructure can’t support that change. They cite a lack of readiness across people, processes, and workflows.&#160; The sticky&#8230;","summary_pt":"Este artigo aborda a crescente lacuna entre ambição e execução na adoção corporativa de IA agêntica. Embora 85% das organizações declarem querer ser \"agênticas\" nos próximos três anos, 76% afirmam que sua infraestrutura e operações atuais não suportam essa mudança. O problema central é que as empresas estão adicionando agentes de IA como \"fita adesiva\" sobre modelos operacionais projetados para humanos, em vez de redesenhar a organização.\r\n\r\nO artigo apresenta o conceito de Agentic Business Transformation (ABT), estruturado em três pilares: a stack tecnológica (que deve ser reconfigurada para que agentes atuem como tecido conectivo); a força de trabalho (onde gestores precisarão gerenciar equipes híbridas humano-agente); e as métricas de sucesso (que devem migrar de outputs para outcomes).\r\n\r\nPara líderes empresariais, a conclusão prática é que implantar IA agêntica sem redesenhar o modelo operacional, a força de trabalho e as métricas de sucesso é uma receita para frustração e desaceleração do ROI. A transformação agêntica é uma mudança de sistema, não uma iniciativa pontual de tecnologia.","source_id":"mit","first_seen":"2026-05-31","pub_date":"2026-05-26"},{"title":"Japanâs $100 billion opportunity in general-purpose robotics","title_pt":"A oportunidade de US$ 100 bilhões do Japão em robótica de uso geral","url":"https://www.mckinsey.com/industries/industrials/our-insights/japans-100-billion-opportunity-in-general-purpose-robotics","summary":"Can Japan translate its hardware expertise into AI, data, and software to emerge as a leader as general-purpose robots scale?","summary_pt":"Este artigo da McKinsey examina como o Japão, historicamente líder em robótica industrial, corre o risco de perder protagonismo na próxima onda da robótica: máquinas de uso geral alimentadas por IA avançada. O mercado global de robótica de uso geral deve crescer de menos de US$ 1 bilhão em 2025 para US$ 370 bilhões em 2040. O Japão almeja capturar 30% desse mercado, mas enfrenta déficits sérios: perde para China e EUA em patentes de humanoides, em ecossistemas de startups e em velocidade de comercialização.\r\n\r\nO artigo detalha duas abordagens competitivas emergentes: a chinesa (hardware-first, foco em implantação massiva para coleta de dados) e a americana (AI-centric, prioridade em autonomia e software). Para os fabricantes japoneses, os autores recomendam aproveitar a tradição de coordenação precisa de componentes para criar plataformas de software unificadas e desenvolver modelos de negócio de Robotics as a Service (RaaS).\r\n\r\nA conclusão é inequívoca: a próxima fase da competição em robótica não será vencida apenas por hardware — dependerá de como as empresas combinam engenharia de precisão com IA, dados e implantação em larga escala.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-26"},{"title":"The Download: puncturing the AI jobs panic","title_pt":"O Download: desmistificando o pânico sobre IA e empregos","url":"https://www.technologyreview.com/2026/05/26/1138028/the-download-ai-jobs-data/","summary":"This is today&#8217;s edition of The Download, our weekday newsletter that provides a daily dose of what&#8217;s going on in the world of technology. A reality check on the AI jobs hysteria Despite the growing hysteria over AI’s threat to white-collar jobs, there’s still scant evidence that the technology has had a large-scale impact on&#8230;","summary_pt":"Esta edição do The Download da MIT Technology Review confronta a narrativa dominante sobre o impacto da IA no mercado de trabalho com o que os dados realmente mostram. A análise dos dados trabalhistas dos EUA revela que o desemprego nas ocupações mais expostas à IA está, na verdade, mais baixo do que em empregos menos expostos. Também não há sinais de migrações em massa de trabalhadores de profissões ameaçadas para empregos manuais.\r\n\r\nEm paralelo, um artigo de opinião alerta para um problema mais silencioso: a IA pode estar enfraquecendo o primeiro degrau da escada de carreira. Um estudo de Stanford encontrou queda acentuada no emprego de trabalhadores jovens em ocupações expostas à IA após a disseminação da IA generativa, sugerindo que a tecnologia está substituindo as tarefas juniores que antes davam aos jovens sua primeira experiência profissional.\r\n\r\nPara líderes empresariais, a mensagem prática é clara: ao invés de reagir a manchetes alarmistas, é necessário adotar uma análise granular de como a IA está afetando diferentes segmentos da força de trabalho.","source_id":"mit","first_seen":"2026-05-31","pub_date":"2026-05-26"},{"title":"The next era of healthcare is personal","title_pt":"A próxima era da saúde é pessoal","url":"https://www.mckinsey.com/industries/life-sciences/our-insights/the-next-era-of-healthcare-is-personal","summary":"Moderna CEO StÃ©phane Bancel explains how mRNA, AI, and individualized care could transform everything from vaccines to cancer treatment.","summary_pt":"Neste podcast da McKinsey, Stéphane Bancel, CEO da Moderna, explica como a tecnologia mRNA e a IA estão inaugurando uma nova era de medicina personalizada que rompe com o modelo de \"tamanho único para todos\". A ideia central é que a biologia é fundamentalmente uma ciência baseada em informação: o mRNA é uma molécula de informação que instrui as células a produzirem respostas imunológicas específicas, permitindo que medicamentos sejam projetados como software.\r\n\r\nO exemplo mais concreto é o tratamento individualizado para câncer de pele: se dois pacientes forem diagnosticados com melanoma no mesmo dia, a Moderna produzirá um medicamento quimicamente diferente para cada um, baseado na instabilidade específica do DNA de cada pessoa. Dados de cinco anos de sobrevivência mostram 50% de melhoria em relação ao tratamento padrão.\r\n\r\nA IA está acelerando dois fronts: na descoberta de medicamentos, robôs realizam experimentos e dados retroalimentam sistemas de IA em ciclos contínuos; na operação corporativa, a empresa integra IA em RH, vendas, manufatura robótica e gestão de qualidade. Para líderes de saúde e tecnologia, a medicina personalizada em escala industrial não é ficção científica, mas uma realidade comercial a dois anos de distância.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-21"},{"title":"Global Banking Annual Review 2026: Precision with speed","title_pt":"Revisão Anual Global de Bancos 2026: Precisão com velocidade","url":"https://www.mckinsey.com/industries/financial-services/our-insights/global-banking-annual-review","summary":"In this preview of our 2026 Global Banking Annual Review, we provide a glimpse of banksâ continued strong results in 2025; the emergence of a new world map; the tipping point for customer ownership; and the unprecedented pace at which AI is remaking the industry, prompting banks to accelerate their precision strategies and evolve into multispeed organizations.","summary_pt":"O relatório anual da McKinsey sobre o setor bancário global registra outro ano de resultados recordes: lucro líquido global de US$ 1,3 trilhão em 2025, alta de 7% sobre 2024. Ao mesmo tempo, o relatório lança um alerta: os múltiplos de valuation dos bancos continuam sendo os mais baixos de qualquer setor, sugerindo que investidores não acreditam que o desempenho atual seja sustentável.\r\n\r\nO relatório identifica quatro ameaças convergentes: fintechs maduras que já respondem por 17% das receitas combinadas com bancos tradicionais; neobancos como Revolut (69 milhões de clientes, ROE de 35%) e Nubank (131 milhões de clientes, ROE de 30%); IA agêntica e stablecoins que permitem que clientes otimizem depósitos e crédito sem os bancos tradicionais; e mudança no comportamento dos consumidores jovens, cuja confiança em fintechs já supera a dos bancos tradicionais.\r\n\r\nA resposta estratégica preconizada é \"precisão com velocidade\": os bancos que adotarem IA de forma estratégica — não necessariamente os maiores, mas os mais ágeis — capturarão participação de mercado dos retardatários em ritmo acelerado e sem precedentes históricos.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-21"},{"title":"Author Talks: Testing AIâs limits in a one-year experiment","title_pt":"Conversas com Autores: Testando os limites da IA em um experimento de um ano","url":"https://www.mckinsey.com/featured-insights/mckinsey-on-books/author-talks-testing-ais-limits-in-a-one-year-experiment","summary":"What happens when AI runs your life for a year? NBC News Chief Technology Analyst Joanna Stern reveals surprising gainsâand unsettling trade-offsâto embedding AI into everything from labor to leisure.","summary_pt":"Este conteúdo no formato \"Author Talks\" da McKinsey apresenta uma conversa com um autor que realizou um experimento prático de um ano para explorar e testar os limites reais da inteligência artificial em contextos profissionais e criativos. O formato da McKinsey costuma combinar entrevistas com insights práticos aplicáveis a líderes empresariais sobre como usar IA de forma inteligente e responsável, evitando tanto o ceticismo excessivo quanto o entusiasmo acrítico.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-20"},{"title":"For industrials, the next decade belongs to builders","title_pt":"Para empresas industriais, a próxima década pertence aos construtores","url":"https://www.mckinsey.com/capabilities/business-building/our-insights/for-industrials-the-next-decade-belongs-to-builders","summary":"As core growth stalls, a small set of AI-enabled business-building plays is emerging as the fastest path to new revenue for industrial and energy leaders that know how to execute successfully.","summary_pt":"O artigo da McKinsey argumenta que, no setor industrial, a próxima década será definida por empresas e líderes que adotam uma postura proativa de construção — seja de novos negócios, capacidades digitais ou modelos operacionais — em vez de apenas otimizar o que já existe. O foco em \"builders\" sugere que a vantagem competitiva no setor industrial virá da capacidade de criar ativamente novas fontes de valor, aproveitando tendências como IA, automação e transição energética.\r\n\r\nA mensagem central é que empresas industriais tradicionais que ficarem presas em ciclos de otimização incremental perderão para novos entrantes mais ágeis que constroem ao redor das tecnologias emergentes. Para líderes do setor, o momento de agir é agora — a janela para construir vantagens duradouras está se fechando.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-19"},{"title":"Google just redesigned the search box for the first time in 25 years — here’s why it matters more than you think.","title_pt":"Google redesenha a caixa de busca pela primeira vez em 25 anos — e por que isso importa mais do que parece","url":"https://venturebeat.com/technology/google-just-redesigned-the-search-box-for-the-first-time-in-25-years-heres-why-it-matters-more-than-you-think","summary":"For a quarter century, the Google search box has been one of the most recognizable interfaces in computing: a thin white rectangle, a blinking cursor, a few typed words, and a list of blue links. On Tuesday, Google will formally retire that paradigm.At its annual I/O developer conference, Google announced a sweeping redesign of the search box itself — the literal text field where billions of qu...","summary_pt":"Por um quarto de século, a caixa de busca do Google foi uma das interfaces mais reconhecíveis da computação: um retângulo branco, um cursor piscante, algumas palavras digitadas e uma lista de links azuis. No Google I/O de 2026, a empresa anunciou a reformulação mais profunda desse paradigma desde o lançamento do buscador — a primeira mudança real na interface de busca em 25 anos.\r\n\r\nA nova interface reflete o reposicionamento estratégico do Google diante da IA generativa: em vez de retornar listas de links, a busca passa a interpretar intenções e fornecer respostas geradas por modelos de linguagem. A mudança vai além da estética — representa uma transformação no modelo de negócio publicitário que sustentou a empresa por décadas.\r\n\r\nPara líderes de marketing digital e estratégia de conteúdo, as implicações são diretas: as estratégias de SEO baseadas em posicionamento de links perdem relevância, e a presença nos resultados de IA passa a ser o novo campo de batalha pela atenção dos usuários. Quem não adaptar suas estratégias de conteúdo para ser citado por modelos de IA poderá perder visibilidade significativa nos próximos anos.","source_id":"venturebeat","first_seen":"2026-06-01","pub_date":"2026-05-19"},{"title":"Renewables O&M reimagined: Boosting performance with AI and conventional levers","title_pt":"Operação e manutenção de renováveis reimaginadas: melhorando o desempenho com IA e alavancas convencionais","url":"https://www.mckinsey.com/industries/electric-power-and-natural-gas/our-insights/renewables-o-and-m-reimagined-boosting-performance-with-ai-and-conventional-levers","summary":"Operators with growing onshore wind and solar PV portfolios can unlock hidden value by using a mix of conventional techniques and AI to optimize their operations and maintenance strategies.","summary_pt":"O setor de energia renovável, especialmente eólica onshore e solar fotovoltaica, cresce rapidamente — mas juros altos, inflação e queda nos preços de energia estão comprimindo margens. A análise da McKinsey revela uma lacuna de desempenho de 12 a 15% entre portfólios medianos e os de melhor desempenho, com valor potencial não capturado de até 9,1 milhões de euros por GW ao ano em eólica onshore.\r\n\r\nO artigo defende que a operação e manutenção (O&M) representa uma oportunidade significativa e frequentemente negligenciada. Ferramentas de manutenção preditiva baseadas em dados, agendamento otimizado por IA generativa, pacotes de trabalho digitais para técnicos em campo e gestão autônoma de inventário podem transformar operações fragmentadas em sistemas integrados e prescritivos.\r\n\r\nPara líderes do setor, rever a estratégia de O&M não é apenas uma oportunidade — é um imperativo competitivo. Em um ambiente onde as margens estão sob pressão, operadores que combinam técnicas convencionais sólidas com soluções habilitadas por IA estarão melhor posicionados para sustentar a rentabilidade de seus portfólios crescentes.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-18"},{"title":"From AI table stakes to AI advantage: Building competitive moats","title_pt":"De requisito básico de IA a vantagem competitiva: construindo fossos defensáveis","url":"https://www.mckinsey.com/capabilities/quantumblack/our-insights/from-ai-table-stakes-to-ai-advantage-building-competitive-moats","summary":"When everyone has access to the same AI models, the winners are those who use them to build advantages that competitors canât copy.","summary_pt":"O artigo parte de uma constatação central: com quase 90% das organizações usando IA em pelo menos uma função de negócios, o acesso aos mesmos grandes modelos de linguagem está se tornando onipresente — e, portanto, não constitui diferencial. Assim como apps e sites não geraram vantagem sustentável por si sós, a adoção genérica de IA tampouco garante retornos superiores. A verdadeira competição agora se dá na capacidade de transformar modelos comuns em fossos competitivos difíceis de replicar.\r\n\r\nOs autores identificam seis fossos estratégicos: economias de escala, dados privilegiados, embeddedness (soluções indispensáveis ao integrar fluxos de trabalho centrais), efeitos de rede, disrupção de modelo de negócio, e ativos físicos escassos. O artigo traz exemplos quantificados: a DBS Bank reduziu o tempo de desenvolvimento de soluções de IA de 12-18 meses para 2-3 meses; o JPMorgan Chase reporta retornos de IA próximos a US$ 2 bilhões anuais.\r\n\r\nPara CEOs e conselhos, a prescrição é objetiva: identificar um a três fossos onde se tem vantagem estrutural e construir os sistemas habilitadores que os reforcem ao longo do tempo. Em um ambiente onde os modelos se tornam commodities, vencer significa ser a organização que mais rapidamente converte modelos comuns em fossos incomuns.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-15"},{"title":"Where AI is creating real value in real estate","title_pt":"Onde a IA está criando valor real no mercado imobiliário","url":"https://www.mckinsey.com/featured-insights/mckinsey-explainers/where-ai-is-creating-real-value-in-real-estate","summary":"Agentic AI is moving real estate beyond isolated tools toward full workflow transformationâunlocking new value, redefining roles, and reshaping how organizations operate.","summary_pt":"O artigo argumenta que a adoção de IA no setor imobiliário está acelerando, mas a maioria das iniciativas ainda se concentra em automação de tarefas isoladas, sem transformar fluxos de trabalho de ponta a ponta. O Instituto Global McKinsey estima que a IA pode desbloquear entre US$ 430 bilhões e US$ 550 bilhões em valor ao longo da cadeia imobiliária.\r\n\r\nO diferencial entre experimentação e transformação real reside em três práticas: vincular investimentos em IA a impacto mensurável no P&L, ter patrocínio sênior tratando a IA como iniciativa estratégica central, e adotar uma abordagem por domínios — redesenhando fluxos de trabalho completos como locação, operações prediais e gestão de ativos, em vez de automatizar passos individuais. Essa abordagem permite ganhos de 10% a 30% em indicadores como receita operacional líquida.\r\n\r\nOs domínios com maior criação de valor incluem instalações e manutenção (triagem de chamados, resolução mais rápida), locação (modelo de atendimento 24/7 que captura mais leads) e operações de back-office onde a IA pode cortar 60% a 80% do tempo necessário.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-15"},{"title":"HackerOne CEO Kara Sprague on how AI is reshaping cybersecurity","title_pt":"CEO da HackerOne, Kara Sprague, sobre como a IA está remodelando a cibersegurança","url":"https://www.mckinsey.com/capabilities/mckinsey-technology/our-insights/hackerone-ceo-kara-sprague-on-how-ai-is-reshaping-cybersecurity","summary":"HackerOne CEO Kara Sprague discusses how AI is reshaping the cybersecurity landscape and why security teams must shift from finding vulnerabilities to reducing exposure.","summary_pt":"Em entrevista ao sênior partner da McKinsey, a CEO da HackerOne Kara Sprague descreve um cenário de transformação estrutural na cibersegurança: a superfície de ataque está crescendo (mais modelos de IA e código gerado por IA sendo implantados), essa superfície é mais vulnerável (segurança para implantações de IA ainda é nascente), e os atacantes estão se tornando mais capazes ao adotar modelos de fronteira. O tempo entre descoberta e exploração de vulnerabilidades caiu de mais de dois anos em 2018 para menos de um dia hoje.\r\n\r\nOs dados da HackerOne revelam um aumento de 76% nos relatórios de vulnerabilidades ano a ano. A raiz do problema está nos pontos de handoff do fluxo de trabalho tradicional — encontrar, registrar, triar, priorizar e corrigir — que criam acúmulos que não suportam volume crescente.\r\n\r\nA resposta exige repensar o modelo operacional de segurança com IA no centro: testes agênticos que replicam o que adversários fariam, validação agêntica para absorver a explosão de volume, e suporte a remediação para acelerar o caminho de achado a correção verificada. Para líderes de tecnologia, a vantagem não irá para a organização que encontrar mais vulnerabilidades, mas para aquela que reduzir sua exposição ao risco mais rapidamente.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-14"},{"title":"The AI assembly line: Strategic imperatives for CEOs","title_pt":"A linha de montagem de IA: imperativos estratégicos para CEOs","url":"https://www.mckinsey.com/industries/industrials/our-insights/the-ai-assembly-line-strategic-imperatives-for-ceos","summary":"AI has proven its potential, but value remains hard to scale. To turn experimentation into sustained performance, CEOs must reimagine their organizations.","summary_pt":"O artigo utiliza a metáfora da linha de montagem de Ford para argumentar que a IA agêntica representa para o trabalho cognitivo o mesmo que a linha de montagem representou para o trabalho físico: uma reorganização fundamental que não é apenas tecnológica, mas cultural e organizacional. Assim como Ford reduziu o tempo de montagem de um Model T de 12 horas para 90 minutos, a IA agêntica pode comprimir ciclos de decisão de semanas para minutos.\r\n\r\nO problema central identificado é que a maioria das empresas trata a IA como projeto de tecnologia aplicado a domínios funcionais isolados — e colhe apenas retornos incrementais. Para escalar valor, CEOs devem agir como arquitetos-chefes da transformação: quebrar silos entre times de tecnologia e negócio, padronizar dados e ferramentas, e redefinir metas de talentos.\r\n\r\nA infraestrutura tecnológica central é a camada de orquestração agêntica — uma plataforma que gerencia o fluxo de tarefas entre agentes funcionais e agentes empresariais. Casos concretos: a Toshiba Tec expandiu a cobertura de personalização de catálogos de 8% para quase 100%; uma montadora reduziu custos de capital de giro em 20% e gerou US$ 200 milhões de lucro adicional no primeiro ano.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-13"},{"title":"How agility and AI could rewire agriculture trading","title_pt":"Como agilidade e IA podem reconectar o trading agrícola","url":"https://www.mckinsey.com/industries/agriculture/our-insights/how-agility-and-ai-could-rewire-agriculture-trading","summary":"Global forces and algorithmic price discovery are reshaping agriculture trading. Traders and processors with agile, analyticsâdriven organizations could define the next competitive frontier.","summary_pt":"O artigo contextualiza uma virada estrutural nos mercados agrícolas: em 2025, o pool de lucros do trading de commodities agrícolas caiu 15% em relação ao ano anterior, pressionado por volatilidade climática crescente, políticas comerciais imprevisíveis, novas regulações de biocombustíveis e gargalos logísticos. O ambiente de 2026 é ainda mais complexo, com o fechamento do Estreito de Ormuz impactando fluxos globais de fertilizantes.\r\n\r\nTrês tendências estão redefinindo o setor: maior variabilidade de oferta (eventos climáticos extremos, disrupções geopolíticas); entrada de novos participantes sofisticados (hedge funds com estratégias quantamentais, majors de petróleo expandindo para biocombustíveis); e descoberta de preços mais rápida via algoritmos, que estão comprimindo o tempo disponível para os traders agirem sobre sinais fundamentais.\r\n\r\nPara traders e processadores, o artigo propõe quatro alavancas de transformação: otimização global da cadeia de valor, modelo operacional ágil com ciclos de planejamento mais curtos, melhoria de qualidade e transparência de dados, e portfólios de analytics ágeis. A IA agêntica em operações pós-negociação deve melhorar a produtividade em 30% a 60% nos próximos dois a quatro anos.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-12"},{"title":"Agents, robots, and us: How AI reshapes work and skills in Europe","title_pt":"Agentes, robôs e nós: como a IA remodela o trabalho e as competências na Europa","url":"https://www.mckinsey.com/mgi/our-research/agents-robots-and-us-how-ai-reshapes-work-and-skills-in-europe","summary":"Most skills will still be neededâbut how people use them will change as they work alongside intelligent machines.","summary_pt":"Este relatório do McKinsey Global Institute analisa dez economias europeias representando mais de três quartos da força de trabalho e do PIB da região. A conclusão central é que 58% das horas de trabalho atuais na Europa poderiam teoricamente ser automatizadas com tecnologias existentes — 44% por agentes de IA para tarefas cognitivas e 14% por robôs para trabalho físico.\r\n\r\nO valor econômico potencial é estimado entre US$ 1,1 trilhão (cenário gradual) e US$ 1,9 trilhão (cenário de adoção mais rápida) até 2030, com agentes de IA respondendo por 82% desse valor. A Alemanha lidera com US$ 486 bilhões de potencial, seguida pelo Reino Unido (US$ 375 bilhões) e França (US$ 238 bilhões).\r\n\r\nUm achado central e contra-intuitivo é que 75% das competências demandadas por empregadores europeus são usadas tanto em atividades automatizáveis quanto não automatizáveis — o que significa que a maioria das habilidades será aplicada em colaboração com IA, não simplesmente substituída. Para empresas e formuladores de políticas, redesenhar fluxos de trabalho (não apenas automatizar tarefas isoladas) é o que converte potencial técnico em valor econômico real.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-12"},{"title":"The McKinsey Crossword: Made with AI | No. 266","title_pt":"Palavras Cruzadas da McKinsey: Feito com IA | N.o 266","url":"https://www.mckinsey.com/featured-insights/the-mckinsey-crossword/may-2026","summary":"Sharpen your problem-solving skills with the McKinsey Quarterly crossword. Each puzzle is created with the McKinsey audience in mind and is built around a subtle (and sometimes not-so-subtle) business theme for you to find.","summary_pt":"Edição de maio de 2026 das palavras cruzadas interativas da McKinsey Quarterly, criada com auxílio de IA e voltada ao público de negócios.","source_id":"mckinsey","first_seen":"2026-05-31","pub_date":"2026-05-11"},{"title":"Railway secures $100 million to challenge AWS with AI-native cloud infrastructure","title_pt":"Railway capta US$ 100 milhões para desafiar a AWS com infraestrutura de nuvem nativa para IA","url":"https://venturebeat.com/infrastructure/railway-secures-usd100-million-to-challenge-aws-with-ai-native-cloud","summary":"Railway, a San Francisco-based cloud platform that has quietly amassed two million developers without spending a dollar on marketing, announced Thursday that it raised $100 million in a Series B funding round, as surging demand for artificial intelligence applications exposes the limitations of legacy cloud infrastructure.TQ Ventures led the round, with participation from FPV Ventures, Redpoint...","summary_pt":"A Railway, plataforma de nuvem baseada em San Francisco que acumulou dois milhões de desenvolvedores sem gastar um centavo em marketing, anunciou uma rodada Série B de US$ 100 milhões liderada pela TQ Ventures, com participação de FPV Ventures, Redpoint e outros. A captação ocorre em um momento em que a demanda explosiva por aplicações de inteligência artificial expõe as limitações da infraestrutura de nuvem tradicional.\r\n\r\nAo contrário das grandes provedoras de nuvem, a Railway se posiciona como uma plataforma de deploy simplificada e nativamente adaptada para cargas de trabalho de IA — reduzindo a complexidade operacional que costuma acompanhar implantações em AWS, GCP ou Azure. O modelo de crescimento orgânico, baseado em boca a boca entre desenvolvedores, é um diferencial relevante em um mercado dominado por grandes gastos em marketing.\r\n\r\nPara líderes de engenharia e CTOs, a Railway representa uma aposta interessante na simplificação do stack de infraestrutura para IA — especialmente para equipes que buscam velocidade de deploy sem o overhead operacional das nuvens tradicionais. O crescimento da base de usuários sem investimento em marketing sugere forte product-market fit e relevância real no ecossistema de desenvolvimento.","source_id":"venturebeat","first_seen":"2026-06-01","pub_date":"2026-01-22"},{"title":"Claude Code costs up to $200 a month. Goose does the same thing for free.","title_pt":"Claude Code custa até US$ 200 por mês. O Goose faz o mesmo de graça.","url":"https://venturebeat.com/infrastructure/claude-code-costs-up-to-usd200-a-month-goose-does-the-same-thing-for-free","summary":"The artificial intelligence coding revolution comes with a catch: it&#x27;s expensive.Claude Code, Anthropic&#x27;s terminal-based AI agent that can write, debug, and deploy code autonomously, has captured the imagination of software developers worldwide. But its pricing — ranging from $20 to $200 per month depending on usage — has sparked a growing rebellion among the very programmers it aims ...","summary_pt":"A revolução da IA no desenvolvimento de software tem um preço elevado. O Claude Code, agente de terminal da Anthropic capaz de escrever, depurar e implantar código de forma autônoma, conquistou a imaginação de desenvolvedores em todo o mundo — mas sua precificação, que varia de US$ 20 a US$ 200 mensais dependendo do uso, gerou crescente resistência entre os próprios programadores que deveria beneficiar.\r\n\r\nSurgindo como alternativa de código aberto, o Goose — desenvolvido pela Block — oferece capacidades similares de agente de codificação sem custo de assinatura. A comparação expõe uma tensão estrutural no mercado de ferramentas de IA para desenvolvedores: a adoção acelerada criou dependência de ferramentas pagas, enquanto o ecossistema open source responde com alternativas cada vez mais competitivas.\r\n\r\nPara equipes de engenharia e líderes de TI, a escolha entre ferramentas pagas com suporte robusto e alternativas gratuitas com maior risco operacional tornou-se uma decisão estratégica relevante. O custo total de propriedade das ferramentas de IA para desenvolvimento precisa ser avaliado com rigor — custos variáveis baseados em tokens podem tornar orçamentos de engenharia imprevisíveis à medida que o uso escala.","source_id":"venturebeat","first_seen":"2026-06-01","pub_date":"2026-01-19"},{"title":"Listen Labs raises $69M after viral billboard hiring stunt to scale AI customer interviews","title_pt":"Listen Labs capta US$ 69 milhões após viral de outdoor com tokens de IA para escalar entrevistas com clientes","url":"https://venturebeat.com/technology/listen-labs-raises-usd69m-after-viral-billboard-hiring-stunt-to-scale-ai","summary":"Alfred Wahlforss was running out of options. His startup, Listen Labs, needed to hire over 100 engineers, but competing against Mark Zuckerberg&#x27;s $100 million offers seemed impossible. So he spent $5,000 — a fifth of his marketing budget — on a billboard in San Francisco displaying what looked like gibberish: five strings of random numbers.The numbers were actually AI tokens. Decoded, they...","summary_pt":"Alfred Wahlforss, fundador da Listen Labs, estava sem opções: sua startup precisava contratar mais de 100 engenheiros, mas competir com os pacotes de US$ 100 milhões oferecidos por Mark Zuckerberg parecia impossível. A solução foi gastar US$ 5.000 — um quinto do orçamento de marketing — em um outdoor em San Francisco exibindo o que parecia ser nonsense: cinco sequências de números aleatórios. Na verdade, eram tokens de IA que, decodificados, revelavam uma mensagem de recrutamento. A campanha viralizou e trouxe a visibilidade necessária para uma rodada de US$ 69 milhões.\r\n\r\nA Listen Labs desenvolve uma plataforma de entrevistas com clientes alimentada por IA, permitindo que empresas conduzam pesquisas qualitativas em escala sem a necessidade de moderadores humanos. Os agentes de IA conduzem entrevistas aprofundadas, fazem perguntas de acompanhamento e sintetizam insights — comprimindo semanas de pesquisa qualitativa em horas.\r\n\r\nPara líderes de pesquisa de mercado, produto e experiência do cliente, a Listen Labs representa uma mudança significativa na forma como insights podem ser coletados. A democratização de entrevistas qualitativas aprofundadas — antes restrita por custo e tempo — abre caminho para ciclos de feedback muito mais frequentes e granulares com usuários reais.","source_id":"venturebeat","first_seen":"2026-06-01","pub_date":"2026-01-16"},{"title":"Salesforce rolls out new Slackbot AI agent as it battles Microsoft and Google in workplace AI","title_pt":"Salesforce lança novo agente de IA no Slackbot em batalha contra Microsoft e Google pela IA corporativa","url":"https://venturebeat.com/technology/salesforce-rolls-out-new-slackbot-ai-agent-as-it-battles-microsoft-and","summary":"Salesforce on Tuesday launched an entirely rebuilt version of Slackbot, the company&#x27;s workplace assistant, transforming it from a simple notification tool into what executives describe as a fully powered AI agent capable of searching enterprise data, drafting documents, and taking action on behalf of employees.The new Slackbot, now generally available to Business+ and Enterprise+ customers...","summary_pt":"A Salesforce anunciou uma reformulação completa do Slackbot, o assistente integrado ao Slack, transformando-o de uma simples ferramenta de notificações em um agente de IA totalmente funcional. O novo Slackbot é capaz de buscar dados empresariais, redigir documentos e executar ações em nome dos colaboradores — disputando diretamente o espaço ocupado pelo Microsoft Copilot e pelo Google Workspace AI.\r\n\r\nDisponível para clientes Business+ e Enterprise+, o novo Slackbot acessa informações de sistemas integrados como Salesforce CRM, ferramentas de RH e outras aplicações corporativas. A Salesforce posiciona o produto como o \"agente nativo\" para times que já vivem dentro do Slack, eliminando a necessidade de alternar entre ferramentas para completar tarefas.\r\n\r\nPara líderes de tecnologia e operações, a guerra pela IA corporativa no ambiente de trabalho se intensifica: quem definir o assistente padrão nos fluxos de trabalho diários ganhará influência significativa sobre produtividade, dados e adoção de novos produtos. A decisão de qual plataforma de IA adotar para o dia a dia das equipes tem implicações estratégicas de longo prazo para o ecossistema de ferramentas corporativas.","source_id":"venturebeat","first_seen":"2026-06-01","pub_date":"2026-01-13"},{"title":"Anthropic launches Cowork, a Claude Desktop agent that works in your files — no coding required","title_pt":"Anthropic lança Cowork, agente do Claude Desktop que trabalha nos seus arquivos — sem precisar programar","url":"https://venturebeat.com/technology/anthropic-launches-cowork-a-claude-desktop-agent-that-works-in-your-files-no","summary":"Anthropic released Cowork on Monday, a new AI agent capability that extends the power of its wildly successful Claude Code tool to non-technical users — and according to company insiders, the team built the entire feature in approximately a week and a half, largely using Claude Code itself.The launch marks a major inflection point in the race to deliver practical AI agents to mainstream users, ...","summary_pt":"A Anthropic lançou o Cowork, uma nova capacidade agêntica que estende o poder do Claude Code — seu produto de maior sucesso — para usuários não técnicos. De acordo com fontes internas, a equipe construiu o recurso inteiro em aproximadamente uma semana e meia, utilizando o próprio Claude Code para isso. O lançamento representa um ponto de inflexão importante na corrida para levar agentes de IA práticos ao público geral.\r\n\r\nAo contrário do Claude Code, que opera via terminal e exige familiaridade técnica, o Cowork atua diretamente sobre arquivos no desktop — analisando documentos, organizando informações, gerando conteúdo e executando tarefas de forma autônoma em interfaces familiares ao usuário comum. Não é necessário escrever código, configurar ambientes ou entender de APIs.\r\n\r\nPara líderes de produto e empresas que buscam democratizar o uso de IA internamente, o Cowork sinaliza que a fronteira da automação agêntica avança rapidamente em direção a usuários sem perfil técnico. Ferramentas que antes exigiam engenheiros para serem operadas passam a ser acessíveis a qualquer colaborador, acelerando a adoção corporativa de IA além dos times técnicos.","source_id":"venturebeat","first_seen":"2026-06-01","pub_date":"2026-01-12"},{"title":"Nous Research's NousCoder-14B is an open-source coding model landing right in the Claude Code moment","title_pt":"NousCoder-14B da Nous Research é modelo open source de codificação que chega no momento do Claude Code","url":"https://venturebeat.com/technology/nous-researchs-nouscoder-14b-is-an-open-source-coding-model-landing-right-in","summary":"Nous Research, the open-source artificial intelligence startup backed by crypto venture firm Paradigm, released a new competitive programming model on Monday that it says matches or exceeds several larger proprietary systems — trained in just four days using 48 of Nvidia&#x27;s latest B200 graphics processors.The model, called NousCoder-14B, is another entry in a crowded field of AI coding assi...","summary_pt":"A Nous Research, startup de IA de código aberto financiada pela Paradigm — firma de venture capital focada em cripto —, lançou o NousCoder-14B, um novo modelo de programação competitivo. Com apenas 14 bilhões de parâmetros, o modelo afirma igualar ou superar sistemas proprietários muito maiores, e foi treinado em apenas quatro dias usando 48 GPUs Nvidia B200.\r\n\r\nO lançamento chega num momento em que ferramentas como o Claude Code dominam a atenção do mercado de desenvolvimento com IA, mas com preços que geram resistência crescente. O NousCoder-14B posiciona-se como uma alternativa open source de alto desempenho para agentes de codificação — potencialmente rodando localmente sem custos de inferência por token.\r\n\r\nPara CTOs, líderes de engenharia e times de plataforma, a chegada de modelos open source competitivos em programação tem implicações práticas relevantes: é possível construir agentes de código internos com controle total sobre dados e propriedade intelectual, sem dependência de APIs externas e sem os custos variáveis que têm gerado atrito no mercado de ferramentas de IA para desenvolvimento.","source_id":"venturebeat","first_seen":"2026-06-01","pub_date":"2026-01-07"}];